// ─── 全域輸入淨化（資安：防 XSS 注入）───
function sanitizeInput(v){
  if(v==null) return '';
  return String(v).replace(/[<>]/g,function(ch){return ch==='<'?'＜':'＞';}).replace(/javascript:/gi,'').replace(/on\w+=/gi,'');
}
function safeVal(id){
  var el=document.getElementById(id);
  return el?sanitizeInput(el.value):'';
}
