// 工時斷路器：派工時記 workStart，checkFatigue 定時掃描
function rtCheckFatigue(){
  var vols=rtGet('volunteers');
  var now=Date.now();
  Object.keys(vols).forEach(function(k){
    var v=vols[k];
    if(v.status==='任務中'&&v.workStart&&!v.fatigue){
      var started=parseInt(v.workStart,10);
      if(started&&(now-started)>6*3600*1000){
        RTDB.ref('volunteers/'+k).update({fatigue:true});
        rtAudit('疲勞警示',k+' '+v.name+' 連續任務逾 6 小時，強制黃燈，禁止派新任務');
        logSys('warn','【疲勞監控】'+v.name+' 連續任務逾 6 小時 → 強制休息');
      }
    }
  });
}
