function simulateUpload(){
  var fid=document.getElementById('ap-site').value;
  var up=(document.getElementById('ap-uploader').value||'志工').trim();
  var desc=(document.getElementById('ap-desc').value||'現場回報').trim();
  var folder=DATA.drive.folders.find(function(x){return x.id===fid;}); if(!folder) return;
  var pid='P'+String(Date.now()).slice(-3);
  var nf={id:pid,name:'IMG_'+pid+'.jpg',type:'photo',category:'未分類',
    size:Math.round(Math.random()*3+1.5).toFixed(1)+' MB',
    uploader:up,time:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'}),
    url:'#',thumb:'📷',status:'待分類'};
  for(var ri=0;ri<DATA.drive.autoRules.length;ri++){
    var rl=DATA.drive.autoRules[ri];
    if(desc.includes(rl.keyword)){nf.category=rl.targetCat;nf.status='已分類';nf.thumb=rl.icon;break;}
  }
  folder.files.unshift(nf);
  logSys('ok','【Drive】'+up+' 上傳 '+nf.name+(nf.status==='已分類'?' → 自動分類:'+nf.category:' → 待分類'));
  toast('📸 上傳完成'+(nf.status==='已分類'?'，自動分類：'+nf.category:'，請手動分類'));
  renderDrive();
}
