          +'</div>'
          +'<div style="font-size:10px;font-weight:500;color:#64748B;margin-bottom:1px">'+f.source+'</div>'
          +'<div style="font-size:12px;color:#CBD5E1;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+f.title+'</div>'
