    +' <span style="font-size:9px;background:var(--purple-bg);color:var(--purple);border:1px solid var(--purple-border);padding:1px 6px;border-radius:6px;font-family:monospace;font-weight:700;margin-left:4px">AI</span></div>'
    +'<div style="font-size:10px;color:var(--text4);margin-bottom:12px;font-weight:500">'+a.note+'</div>';
