let editMode=false;
let hiddenWidgets=new Set();
let disabledModules=new Set();
let dragSrc=null;

function openEdit(wid){
  if(!editMode) return;
  // close others
  document.querySelectorAll('.inline-edit-panel.show').forEach(p=>p.classList.remove('show'));
  const panel=document.getElementById('iep-'+wid);
  if(!panel) return;
  populateEdit(wid);
  panel.classList.add('show');
}
function closeEdit(wid){
  const panel=document.getElementById('iep-'+wid);
  if(panel) panel.classList.remove('show');
}

function populateEdit(wid){
  if(wid==='w-disaster') buildDisasterEdit();
  if(wid==='w-map')      buildMapEdit();
  if(wid==='w-alerts')   buildAlertsEdit();
  if(wid==='w-manpower') buildManpowerEdit();
  if(wid==='w-ai')       buildAIEdit();
}

// ── STATS EDIT (per card) ──
function openStatEdit(i){
  if(!editMode) return;
  document.querySelectorAll('.inline-edit-panel.show').forEach(p=>p.classList.remove('show'));
  buildStatEdit(i);
  var panel=document.getElementById('iep-w-stat-'+i);
  if(panel) panel.classList.add('show');
}
function buildStatEdit(i){
  var f=document.getElementById('iep-stat-'+i+'-fields');
  if(!f) return;
  var s=DATA.stats[i];
  var colors=['red','amber','green','blue','purple'];
  var colorMap={red:'#DC2626',amber:'#D97706',green:'#059669',blue:'#2563EB',purple:'#7C3AED'};
  var dots='';
  for(var ci=0;ci<colors.length;ci++){
    var cl=colors[ci];
    var sel=(s.color===cl)?' sel':'';
    dots+='<div class="cp-dot'+sel+'" style="background:'+colorMap[cl]+';width:22px;height:22px;border-radius:50%;cursor:pointer;border:2px solid '+(s.color===cl?'#111':'transparent')+';display:inline-block;margin-right:4px" onclick="pickStatColor('+i+',' + JSON.stringify(cl) + ',this)" title="'+cl+'"></div>';
  }
  f.innerHTML='<div><div class="iep-lbl">標題</div><input class="iep-inp" id="se-lbl-'+i+'" value="'+s.lbl+'"></div>'
    +'<div class="iep-lbl" style="margin-top:6px;color:var(--text4)">'+(s.local?'數值由派案台即時計算（已送達/總需求單）':'數值由 Google Sheets 自動同步（col '+s.col+' row '+s.row+'）')+'</div>'
    +'<div><div class="iep-lbl">說明文字</div><input class="iep-inp" id="se-sub-'+i+'" value="'+s.sub+'"></div>'
    +'<div><div class="iep-lbl">顏色</div><div style="display:flex;gap:4px;margin-top:6px">'+dots+'</div></div>';
}

function pickStatColor(i,col,el){
  DATA.stats[i].color=col;
  el.parentNode.querySelectorAll('.cp-dot').forEach(function(d){d.classList.remove('sel');});
  el.classList.add('sel');
}
function saveStat(i){
  var s=DATA.stats[i];
  s.lbl=document.getElementById('se-lbl-'+i).value||s.lbl;
  s.sub=document.getElementById('se-sub-'+i).value||s.sub;
  renderSingleStat(i);saveData();
  closeEdit('w-stat-'+i);
  toast('✓ 統計卡片 '+(i+1)+' 已更新');
}
