// ══════════════════════════════════════════════════════
//  EDIT MODE TOGGLE
// ══════════════════════════════════════════════════════
function toggleEditMode(){
  if(role!=='sysadmin'){ toast('權限不足','error'); return; }
  editMode=!editMode;
  const btn=document.getElementById('edit-toggle-btn');
  const toolbar=document.getElementById('edit-toolbar');
  const pg=document.getElementById('page-dashboard');
  if(editMode){
    pg.classList.add('edit-mode-on');
    toolbar.classList.add('show');
    if(btn){btn.textContent='✓ 完成編輯';btn.className='btn btn-primary';}
    enableDrag();
    renderNav();
  } else {
    pg.classList.remove('edit-mode-on');
    toolbar.classList.remove('show');
    if(btn){btn.textContent='✏️ 編輯儀表板';btn.className='btn btn-purple';}
    document.querySelectorAll('.inline-edit-panel.show').forEach(p=>p.classList.remove('show'));
    renderNav();
  }
}

// ── WIDGET SHOW/HIDE ──
const WIDGET_NAMES={'w-sim':'情境模擬','w-stat-0':'統計卡片1','w-stat-1':'統計卡片2','w-stat-2':'統計卡片3','w-stat-3':'統計卡片4','w-stat-4':'統計卡片5','w-disaster':'災害範圍','w-map':'地圖進度','w-alerts':'緊急通報','w-manpower':'人力報到','w-ai':'AI預估'};
function hideWidget(id){
  hiddenWidgets.add(id);
  const el=document.getElementById(id);
  if(el) el.classList.add('hidden-widget');
  renderRestoreArea();
}
function showWidget(id){
  hiddenWidgets.delete(id);
  const el=document.getElementById(id);
  if(el) el.classList.remove('hidden-widget');
  renderRestoreArea();
}
function renderRestoreArea(){
  const area=document.getElementById('restore-area');
  if(!area) return;
  area.innerHTML='';
  hiddenWidgets.forEach(id=>{
    const pill=document.createElement('div');
    pill.className='restore-pill';
    pill.onclick=()=>showWidget(id);
    pill.textContent='＋ '+WIDGET_NAMES[id];
    area.appendChild(pill);
  });
}

// ── DRAG SORT ──
function enableDrag(){
  // All widgets: top-level and inside stat row / g2 / g3
  var widgets=document.querySelectorAll(
    '#page-dashboard > .widget,'
    +'#page-dashboard > .g2 > .widget,'
    +'#page-dashboard > .g3 > .widget,'
    +'#w-stats-row > .widget,'
    +'#page-dashboard > .dash-section'
  );
  widgets.forEach(function(w){
    w.setAttribute('draggable','true');
    w.ondragstart=function(e){dragSrc=w;w.style.opacity='.4';e.dataTransfer.effectAllowed='move';};
    w.ondragend=function(){w.style.opacity='';document.querySelectorAll('.widget').forEach(function(x){x.classList.remove('drag-over');});};
    w.ondragover=function(e){e.preventDefault();if(dragSrc&&dragSrc!==w) w.classList.add('drag-over');};
    w.ondragleave=function(){w.classList.remove('drag-over');};
    w.ondrop=function(e){e.stopPropagation();if(dragSrc&&dragSrc!==w&&dragSrc.parentNode===w.parentNode){w.parentNode.insertBefore(dragSrc,w);}};
  });
}

