let currentScenario='quake',currentWarSub='overflow';

function setScenario(id){
  // 再點一次同一個 = 取消選取清空
  if(currentScenario===id){
    currentScenario=null;
    document.querySelectorAll('.sim-btn').forEach(b=>b.classList.remove('sel'));
    document.getElementById('war-subs').style.display='none';
    var lbl=document.getElementById('sim-active-lbl');
    if(lbl) lbl.textContent='當前：未選定';
    var ds=document.getElementById('dash-sub');
    if(ds) ds.textContent='即時災情總覽';
    return;
  }
  currentScenario=id;
  document.querySelectorAll('.sim-btn').forEach(b=>{
    const cls=[...b.classList].find(c=>['wind','flood','fire','quake','war-s','landslide','compound','drought','epidemic','tsunami'].includes(c));
    const match=(id==='war_s'&&cls==='war-s')||(cls===id);
    b.classList.toggle('sel',!!match);
  });
  document.getElementById('war-subs').style.display=id==='war_s'?'block':'none';
  const sc=SCENARIOS[id];
  if(!sc) return;
  document.getElementById('sim-active-lbl').textContent='當前：'+sc.name;
  document.getElementById('dash-sub').textContent='即時災情 · '+sc.sub;
  if(id==='war_s'){applyWarSub(currentWarSub);return;}
  applyScenarioStats(sc.stats);
  renderBugs(sc.bugs);
}
function setWarSub(sub,el){
  currentWarSub=sub;
  document.querySelectorAll('.war-sub').forEach(b=>b.classList.remove('sel'));
  if(el) el.classList.add('sel');
  applyWarSub(sub);
}
function applyWarSub(sub){ const ws=WAR_SUBS[sub]; if(!ws) return; applyScenarioStats(ws.stats); renderBugs([{type:ws.type,badge:'現場情境挑戰',tag:ws.tag,title:ws.title,desc:ws.desc,solLabel:'系統防禦啟動',sol:ws.sol,mods:ws.mods}]); }
function applyScenarioStats(stats){
  for(var i=0;i<stats.length;i++){
    var sv=stats[i];
    DATA.stats[i].lbl = sv.lbl || DATA.stats[i].lbl;
    DATA.stats[i].val = sv.val || DATA.stats[i].val;
    DATA.stats[i].sub = sv.sub || DATA.stats[i].sub;
    DATA.stats[i].color = sv.color || DATA.stats[i].color;
  }
  renderStats();
}
