      +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">'
      +'<span class="bug-badge" style="background:var(--green-bg);color:var(--green);border:1px solid var(--green-border)">&#31995;&#32113;&#22238;&#24212;</span>'
      +'<span style="font-size:9px;font-family:monospace;padding:2px 7px;border-radius:6px;background:white;color:var(--green);border:1px solid var(--green-border);font-weight:700">&#9679; ACTIVE</span>'
      +'</div>'
