      +'<div class="bug-desc">&#20767;&#27979;&#21040;&#12300;'+b.tag+'&#12301;&#65292;&#20197;&#19979;&#27169;&#32068;&#24050;&#33258;&#21160;&#21854;&#21205;&#65306;</div>'
      +'<div style="margin-top:8px">'+mods+'</div>'
