// ══════════════════════════════════════════════════════
// ════════ 即時同步中台層（RTDB）════════
var RTDB=(function(){
  var KEY='drms_rtdb';
  var listeners={};
  var bc=(typeof BroadcastChannel!=='undefined')?new BroadcastChannel('drms_rtdb_sync'):null;
  function readAll(){ try{ var raw=localStorage.getItem(KEY); return raw?JSON.parse(raw):{}; }catch(e){ return {}; } }
  function writeAll(db){ try{ localStorage.setItem(KEY,JSON.stringify(db)); }catch(e){} if(bc) bc.postMessage({t:Date.now()}); }
  function getPath(db,path){ if(!path) return db; var parts=path.split('/'); var cur=db; for(var i=0;i<parts.length;i++){ if(cur==null) return null; cur=cur[parts[i]]; } return (cur===undefined)?null:cur; }
  function setPath(db,path,val){ var parts=path.split('/'); var cur=db; for(var i=0;i<parts.length-1;i++){ if(cur[parts[i]]==null) cur[parts[i]]={}; cur=cur[parts[i]]; } if(val===null) delete cur[parts[parts.length-1]]; else cur[parts[parts.length-1]]=val; return db; }
  function notifyAll(){ Object.keys(listeners).forEach(function(lp){ var db=readAll(); listeners[lp].forEach(function(cb){ try{ cb(getPath(db,lp)); }catch(e){} }); }); }
  if(bc){ bc.onmessage=function(){ notifyAll(); }; }
  return {
    ref:function(path){ path=path||'';
      return {
        on:function(cb){ if(!listeners[path]) listeners[path]=[]; listeners[path].push(cb); cb(getPath(readAll(),path)); return cb; },
        off:function(cb){ if(listeners[path]) listeners[path]=listeners[path].filter(function(f){return f!==cb;}); },
        once:function(cb){ cb(getPath(readAll(),path)); },
        set:function(val){ var db=readAll(); setPath(db,path,val); writeAll(db); notifyAll(); },
        update:function(obj){ var db=readAll(); var cur=getPath(db,path)||{}; for(var k in obj){ cur[k]=obj[k]; } setPath(db,path,cur); writeAll(db); notifyAll(); },
        push:function(val){ var db=readAll(); var id='K'+Date.now().toString(36)+Math.floor(Math.random()*1000); setPath(db,path+'/'+id,val); writeAll(db); notifyAll(); return id; },
        remove:function(){ var db=readAll(); setPath(db,path,null); writeAll(db); notifyAll(); }
      };
    },
    seed:function(data){ var db=readAll(); var empty=true; for(var k in db){empty=false;break;} if(empty){ writeAll(data); } },
    reset:function(data){ writeAll(data); notifyAll(); }
  };
})();
