var navDragSrc=null;
function toggleNavCollapse(){
  var isMobile=window.innerWidth<=768;
  if(isMobile){
    document.body.classList.toggle('nav-open');
  } else {
    document.body.classList.toggle('nav-collapsed');
    localStorage.setItem('drms_nav_collapsed',document.body.classList.contains('nav-collapsed')?'1':'0');
  }
}
function renderNav(){
  var nav=document.getElementById('nav');
  nav.innerHTML='';
  var lastGroup=null;
  // 依角色決定 group 顯示順序
  var groupOrder={
    'it':        ['後台系統','今日行動','現場管理'],
    'admin':     ['後台系統','今日行動','現場管理'],
    'sysadmin':  ['後台系統','今日行動','現場管理'],
    'staff':     ['今日行動','現場管理','後台系統'],
    'logistics': ['今日行動','現場管理','後台系統'],
  }[role]||['今日行動','現場管理','後台系統'];
  var groupColor={'今日行動':'var(--blue)','現場管理':'var(--green)','後台系統':'var(--text4)'};
  // 依 groupOrder 重排
  var sorted=[];
  groupOrder.forEach(function(g){ NAV_CFG.forEach(function(item){ if(item.group===g) sorted.push(item); }); });
  NAV_CFG.forEach(function(item){ if(groupOrder.indexOf(item.group)===-1) sorted.push(item); });
  sorted.forEach(function(item,idx){
    if(disabledModules.has(item.id)&&!editMode){ return; }
    if(item.group&&item.group!==lastGroup){
      var sec=document.createElement('div');
      sec.className='nav-sec';
      sec.style.cssText='border-left:3px solid '+(groupColor[item.group]||'var(--text4)')+';padding-left:7px';
      sec.textContent=item.group;
      nav.appendChild(sec);
      lastGroup=item.group;
    }
    var pval=(PERMS_PEACE[role]&&PERMS_PEACE[role][item.id])||'P1';
    if(role==='admin') pval='P0';
    var ok=(pval!=='P4');
    var el=document.createElement('div');
    el.className='ni'+(activePage===item.id?' act':'')+(ok?'':' locked');
    el.dataset.navIdx=idx;
    var tag='';
    if(item.tag==='core') tag='<span class="ni-tag tag-core">核心</span>';
    if(item.tag==='admin') tag='<span class="ni-tag tag-admin">admin</span>';
    if(item.tag==='limb') tag='<span class="ni-tag" style="background:var(--bg4);color:var(--text4);border:1px solid var(--border)">延伸</span>';
    if(item.tag==='doc') tag='<span class="ni-tag" style="background:var(--blue-bg);color:var(--blue);border:1px solid var(--blue-border)">文件</span>';
    if(item.id==='warehouse'){
      var pend=DATA.warehouse.reqs.filter(function(x){return x.status==='待派案';}).length;
      if(pend>0) tag='<span class="ni-tag" style="background:var(--red-bg);color:var(--red);border:1px solid var(--red-border);animation:blink 1.5s infinite">'+pend+' 待派</span>';
    }
    var grip=editMode?'<span style="cursor:grab;color:var(--purple);font-size:12px;margin-right:2px;flex-shrink:0" title="拖曳排序">⠿</span>':'';
    el.innerHTML=grip+'<span class="ni-icon">'+item.icon+'</span><span class="ni-label">'+item.label+'</span>'+tag;
    if(ok&&!editMode) el.onclick=(function(id){return function(){showPage(id);};})(item.id);
    if(editMode){
      el.setAttribute('draggable','true');
      el.style.border='1px dashed var(--purple-border)';
      el.style.cursor='grab';
      el.ondragstart=function(e){navDragSrc=el;el.style.opacity='.4';e.dataTransfer.effectAllowed='move';};
      el.ondragend=function(){el.style.opacity='';};
      el.ondragover=function(e){e.preventDefault();};
      el.ondrop=function(e){
        e.stopPropagation();
        if(!navDragSrc||navDragSrc===el) return;
        var from=parseInt(navDragSrc.dataset.navIdx);
        var to=parseInt(el.dataset.navIdx);
        var moved=NAV_CFG.splice(from,1)[0];
        NAV_CFG.splice(to,0,moved);
        localStorage.setItem('drms_nav_order',JSON.stringify(NAV_CFG.map(function(x){return x.id;})));
        renderNav();
        logSys('info','【選單排序】'+moved.label+' 已移動（已持久化）');
      };
    }
    nav.appendChild(el);
  });
}
function showPage(id){
  if(disabledModules.has(id)&&id!=='dashboard'){ id='dashboard'; }
  activePage=id;
  // 手機模式：切換頁面後自動收合側欄抽屜
  if(window.innerWidth<=768) document.body.classList.remove('nav-open');
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('act'));
  const pg=document.getElementById('page-'+id);
  if(pg) pg.classList.add('act');
  renderNav();
  // P4 permission guard
  if(role!=='admin'){
    var perms=state==='war'?PERMS_WAR:PERMS_PEACE;
    var pval=(perms[role]&&perms[role][id])||'P1';
    if(pval==='P4'&&pg){
      pg.innerHTML='<div class="no-acc"><div class="ic">🔒</div><h2>權限不足</h2><p>您在此模組的全責規範為 P4（無權限）</p></div>';
    }
  }
  if(id==='vol_hub') renderVolHub();
  if(id==='admin'){
    checkAdminGate();
    renderPermMatrix();renderAPIRows();renderModuleManager();
    renderVersionPanel();
    var su=document.getElementById('cfg-sheet-url');
    if(su) su.value=DATA.field.sheetUrl||'';
    var gu=document.getElementById('cfg-gas-url');
    if(gu) gu.value=DATA.registry.gasUrl||'';
    var igu=document.getElementById('cfg-inner-gas-url');
    if(igu) igu.value=DATA.registry.innerGasUrl||'';
  }
  if(id==='monitor') renderMonitor();
  var mainEl=document.querySelector('.main');
  if(mainEl) mainEl.classList.toggle('arch-fullbleed',id==='arch_doc');
  if(id==='arch_doc') renderArchDoc();
  if(id==='persons') renderPersons();
  if(id==='persons') renderCaseMgt();
  if(id==='care_rec') renderCareRec();
  if(id==='warehouse') renderWarehouse();
  if(id==='shelter_mgt') renderShelterMgt();
  if(id==='relief_req') renderReliefReq();
  if(id==='coord') renderCoord();
  if(id==='rebuild') renderRebuild();
  if(id==='line_oa') renderLineOA();
  if(id==='resources') renderResources();
  if(id==='needs') renderNeeds();
  if(id==='drive') renderDrive();
  if(id==='sorting') renderSorting();
  if(id==='assets') renderAssets();
  if(id==='rtsync'){ renderRTSync(); bindRTListeners(); }
  if(state==='war'&&['persons','persons','warehouse','shelter_mgt'].indexOf(id)>=0&&pg){
    var wb=document.getElementById('war-lock-'+id);
    if(!wb){
      wb=document.createElement('div');
      wb.id='war-lock-'+id;
      wb.style.cssText='background:var(--red-bg);border:1px solid var(--red-border);border-radius:var(--r-sm);padding:8px 14px;font-size:11px;color:var(--red);font-weight:600;margin-bottom:12px';
      wb.innerHTML='🔴 戰時模式 — 平時 Master 資料唯讀鎖定，僅可透過 Line 即時回報通道更新';
      pg.insertBefore(wb,pg.children[1]);
    }
  }
  if(state==='peace'){
    var oldLock=document.getElementById('war-lock-'+id);
    if(oldLock) oldLock.remove();
  }
  if(id==='admin') renderOrgZones();
  const ebw=document.getElementById('edit-btn-wrap');
  if(ebw) ebw.style.display=(id==='dashboard'&&(role==='admin'||role==='sysadmin'))?'block':'none';
}
function checkAdminGate(){
  const gate=document.getElementById('admin-gate');
  if(!gate) return;
  if(role!=='admin'&&role!=='sysadmin'){
    gate.innerHTML='<div class="no-acc"><div class="ic">🔒</div><h2>此頁面僅限總控或系統管理員</h2><p>請切換角色後重試</p></div>';
    return;
  }
  // 角色權限、API設定、版本控制 三個後台 tab 僅 sysadmin 可見
  var isSysadmin=(role==='sysadmin');
  ['admtab-perm','admtab-mod','admtab-ver'].forEach(function(id){
    var el=document.getElementById(id);
    if(el) el.style.display=isSysadmin?'':'none';
  });
}
function setRole(r){
  role=r;
  if(editMode) toggleEditMode();
  if(activePage==='admin'&&r!=='admin'&&r!=='sysadmin') activePage='dashboard';
  var pval=(PERMS_PEACE[role]&&PERMS_PEACE[role][activePage])||'P1';
  if(role==='admin'||role==='sysadmin') pval='P0';
  if(pval==='P4') activePage='dashboard';
  sessionStorage.setItem('drms_role', role);
  showPage(activePage);
  updateFooter();
  renderGmailRows();
  renderLineCards();
}
function setS(s){
  if(role==='sysadmin'&&s==='war'){
    toast('⚠ 請切換至總控角色','error');
    return;
  }
  if(role!=='admin'&&role!=='it'){
    toast('⚠ 權限不足，只有總控或 IT 志工可切換應變狀態');
    return;
  }
  state=s;
  sessionStorage.setItem('drms_state', state);
  document.getElementById('btn-p').className='sbtn'+(s==='peace'?' sp':'');
  document.getElementById('btn-w').className='sbtn'+(s==='war'?' sw':'');
  updateFooter();
  if(s==='war'){
    document.body.classList.add('wt-mode');
    document.getElementById('wt-overlay').classList.add('show');
    // 若平時面板已選定災難，直接帶入並跳到「選等級」，省一個動作
    if(currentScenario&&WAR_MODULE_DEFAULTS[currentScenario]){
      wtPickScenario(currentScenario);
    }
    logSys('info','戰時模式啟動。平時 master 資料已轉唯讀鎖定。LINE OA 密鑰切換為緊急專用頻道。');
    logSys('ok','IT 志工已收到戰時通報，後台維運面板自動開啟。');
    syncActive=true;changeRefreshRate(10000);updateSyncBtn();
  } else {
    document.body.classList.remove('wt-mode');
    endSession();
    restoreAllModulesForPeace();
    logSys('info','已切換回平時模式。所有戰時覆蓋已清除。');
    changeRefreshRate(30000);if(syncActive){startSyncTimer();}updateSyncBtn();
  }
  showPage(activePage);
}
