function renderGmailRows(){
  const wrap=document.getElementById('gmail-rows');
  if(!wrap) return;
  wrap.innerHTML='';
  GROUPS.forEach(g=>{
    const d=document.createElement('div');
    d.className='group-row';
    d.innerHTML='<span style="font-size:16px">'+g.icon+'</span><span style="font-size:12px;font-weight:600;width:72px;flex-shrink:0">'+g.name+'</span><input class="group-email" value="'+g.email+'" placeholder="email@example.com" data-id="'+g.id+'" oninput="updateEmail(this)"><span class="'+(g.email?'gs-ok':'gs-empty')+'" id="gs-'+g.id+'">'+(g.email?'已設定':'未設定')+'</span>';
    wrap.appendChild(d);
  });
}
function updateEmail(inp){
  const g=GROUPS.find(x=>x.id===inp.dataset.id);
  if(g) g.email=inp.value;
  const badge=document.getElementById('gs-'+inp.dataset.id);
  if(badge){badge.className=inp.value?'gs-ok':'gs-empty';badge.textContent=inp.value?'已設定':'未設定';}
}
function renderLineCards(){
  const wrap=document.getElementById('line-group-cards');
  if(!wrap) return;
  wrap.innerHTML='';
  GROUPS.forEach(g=>{
    const card=document.createElement('div');
    card.className='line-group-card'+(g.linked?' linked':'');
    card.innerHTML='<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px"><span style="font-size:20px">'+g.icon+'</span><div><div style="font-size:13px;font-weight:600">'+g.name+'</div><div style="font-size:10px;color:var(--text4)">'+(g.linked?g.line:'尚未串接')+'</div></div><span class="badge '+(g.linked?'badge-green':'badge-red')+'" style="margin-left:auto">'+(g.linked?'已串接':'未串接')+'</span></div><div style="display:flex;gap:6px"><input class="inp" style="flex:1;font-size:11px;font-family:monospace" placeholder="Channel Token" value="'+(g.linked?'••••••••':'')+'" data-lid="'+g.id+'"><button class="btn '+(g.linked?'btn-ghost':'btn-green')+'" style="font-size:11px" onclick="toggleLine(\''+ g.id +'\')">'+(g.linked?'取消':'串接')+'</button></div>';
    wrap.appendChild(card);
  });
}
function toggleLine(id){
  const g=GROUPS.find(x=>x.id===id);
  if(!g) return;
  if(!g.linked){
    // Linking: read token input
    var tokenInp=document.querySelector('[data-lid="'+id+'"]');
    var token=tokenInp?tokenInp.value.replace(/•/g,'').trim():'';
    if(!token){toast('⚠ 請先輸入 Channel Access Token');return;}
    g.linked=true;
    g.token=token;
    g.line='@tzuchi-'+id;
    toast('✅ '+g.name+' Line OA 已串接，Token 已儲存');
  } else {
    g.linked=false; g.line=''; g.token='';
    toast('⚠ '+g.name+' Line OA 已取消串接');
  }
  renderLineCards();
}

// ── REG ──
function maskPII(v,kind){
  if(role==='admin'||role==='it') return v;
  if(kind==='id')    return v.substring(0,3)+'*******';
  if(kind==='phone') return v.substring(0,4)+'***'+v.substring(7);
  if(kind==='email'){ if(!v) return ''; var at=v.indexOf('@'); if(at<2) return (v[0]||'')+'***'+(at>=0?v.substring(at):''); return v.substring(0,2)+'***'+v.substring(at); }
  return v;
}
function makeFunnelRow(items){
  var h='<div style="display:flex;gap:8px;text-align:center;margin-bottom:8px">';
  for(var i=0;i<items.length;i++){
    var it=items[i];
    h+='<div style="flex:1;background:'+it.bg+';border:1px solid '+it.border+';border-radius:var(--r-sm);padding:8px 4px">'
      +'<div style="font-size:20px;font-weight:700;font-family:Inter'+(it.color?';color:'+it.color:'')+'">'
      +it.val+'</div><div style="font-size:9px;color:var(--text4)">'+it.lbl+'</div></div>';
  }
  return h+'</div>';
}
function makeStatGrid(items){
  var h='<div class="stat-grid" style="display:grid;grid-template-columns:repeat('+items.length+',1fr);gap:10px;margin-bottom:14px">';
  for(var i=0;i<items.length;i++){
    var it=items[i];
    h+='<div class="stat-card '+it.color+'" style="padding:12px"><div class="accent-bar"></div>'
      +'<div class="stat-lbl">'+it.lbl+'</div>'
      +'<div class="stat-val" style="font-size:22px">'+it.val+'</div>'
      +'<div class="stat-sub">'+it.sub+'</div></div>';
  }
  return h+'</div>';
}
