function loadTodos(){
  try{ var raw=localStorage.getItem('drms_todos'); if(raw) return JSON.parse(raw); }catch(e){}
  return JSON.parse(JSON.stringify(TODO_DEFAULTS));
}
function saveTodos(list){ try{ localStorage.setItem('drms_todos',JSON.stringify(list)); }catch(e){} }
var TODOS=loadTodos();
function renderTodoList(){
  var el=document.getElementById('todo-list'); if(!el) return;
  if(!TODOS.length){ el.innerHTML='<div style="font-size:12px;color:var(--text4);text-align:center;padding:20px 0">目前無待辦項目</div>'; return; }
  var pColor={P1:'red',P2:'amber',P3:'blue'};
  var html='';
  for(var i=0;i<TODOS.length;i++){
    var t=TODOS[i];
    var dim=t.done?'opacity:.5':'';
    html+='<div style="border:1px solid var(--border);border-radius:var(--r-sm);padding:14px 16px;margin-bottom:10px;background:var(--bg2);'+dim+'">';
    html+='<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">';
    html+='<span class="badge badge-'+(pColor[t.pri]||'blue')+'">'+t.pri+'</span>';
    html+='<span style="font-size:13px;font-weight:700;flex:1;'+(t.done?'text-decoration:line-through':'')+'">'+esc(t.title)+'</span>';
    html+='<button class="btn btn-ghost btn-xs" onclick="toggleTodo('+i+')">'+(t.done?'↺ 重開':'✓ 完成')+'</button>';
    html+='<button class="btn btn-ghost btn-xs" onclick="editTodo('+i+')">✎</button>';
    html+='<button class="btn btn-ghost btn-xs" style="color:var(--red)" onclick="delTodo('+i+')">✕</button>';
    html+='</div>';
    html+='<div style="font-size:11px;line-height:1.8;color:var(--text2)">';
    html+='<div style="margin-bottom:3px"><b style="color:var(--text3)">背景：</b>'+esc(t.bg)+'</div>';
    html+='<div style="margin-bottom:3px"><b style="color:var(--text3)">為何重要：</b>'+esc(t.why)+'</div>';
    html+='<div><b style="color:var(--text3)">技術方向：</b>'+esc(t.how)+'</div>';
    html+='</div></div>';
  }
  el.innerHTML=html;
}
function toggleTodo(i){ TODOS[i].done=!TODOS[i].done; saveTodos(TODOS); renderTodoList(); }
function delTodo(i){ if(!confirm('刪除「'+TODOS[i].title+'」？')) return; TODOS.splice(i,1); saveTodos(TODOS); renderTodoList(); toast('🗑 已刪除'); }
function addTodo(){
  var title=prompt('待辦標題：'); if(!title||!title.trim()) return;
  var pri=prompt('優先級（P1/P2/P3）：','P2')||'P2';
  TODOS.unshift({pri:pri.trim().toUpperCase(),title:title.trim(),bg:'(待補)',why:'(待補)',how:'(待補)',done:false});
  saveTodos(TODOS); renderTodoList(); toast('＋ 已新增');
}
function editTodo(i){
  var t=TODOS[i];
  var title=prompt('標題：',t.title); if(title===null) return;
  var bg=prompt('背景：',t.bg); if(bg===null) return;
  var why=prompt('為何重要：',t.why); if(why===null) return;
  var how=prompt('技術方向：',t.how); if(how===null) return;
  t.title=title.trim()||t.title; t.bg=bg; t.why=why; t.how=how;
  saveTodos(TODOS); renderTodoList(); toast('✎ 已更新');
}

