// Permission matrix  { roleId: { moduleId: 'P0'|'P1'|'P2'|'P3'|'P4' } }
// peacetime: admin=P0 always, others default P1
// wartime: admin=P0 always, others default P1
function defaultPerms(moduleId, roleId, tab) {
  if (roleId === 'admin') return 'P0';
  if (roleId === 'it' && tab !== 'wartime') return 'P0';
  return 'P1';
}
let PERMS_PEACE = {};
let PERMS_WAR   = {};
function initPerms() {
  MODULES_PEACE.forEach(m => {
    ROLES.forEach(r => {
      if (!PERMS_PEACE[r.id]) PERMS_PEACE[r.id] = {};
      if (!PERMS_PEACE[r.id][m.id]) PERMS_PEACE[r.id][m.id] = defaultPerms(m.id, r.id, 'peacetime');
    });
  });
  MODULES_WAR.forEach(m => {
    ROLES.forEach(r => {
      if (!PERMS_WAR[r.id]) PERMS_WAR[r.id] = {};
      if (!PERMS_WAR[r.id][m.id]) PERMS_WAR[r.id][m.id] = defaultPerms(m.id, r.id, 'wartime');
    });
  });
}
initPerms();

