// 後台可覆寫預設（儲存在 localStorage）
function loadWarModuleDefaults(){
  try{
    var raw=localStorage.getItem('drms_war_modules_v2');
    if(raw){ var saved=JSON.parse(raw); for(var k in saved){ if(WAR_MODULE_DEFAULTS[k]&&saved[k]) WAR_MODULE_DEFAULTS[k].levels=saved[k]; } }
  }catch(e){}
}
function saveWarModuleDefaults(){
  var out={};
  for(var k in WAR_MODULE_DEFAULTS) out[k]=WAR_MODULE_DEFAULTS[k].levels;
  localStorage.setItem('drms_war_modules_v2',JSON.stringify(out));
}
var _wtPendingScenario='quake';
var _wtPendingLevel='L1';
function wtPickScenario(id){
  _wtPendingScenario=id;
  var def=WAR_MODULE_DEFAULTS[id]||WAR_MODULE_DEFAULTS['quake'];
  var s1=document.getElementById('wt-step1');
  var s1b=document.getElementById('wt-step1b');
  if(s1) s1.style.display='none';
  if(s1b) s1b.style.display='block';
  var t=document.getElementById('wt-s1b-title');
  if(t) t.textContent=def.emoji+' '+def.label+' — 選擇受災規模';
  // 動態填入各級模組數，選前即知開幾個
  var lv=def.levels||{};
  function cnt(x){ return (lv[x]&&lv[x].modules)?lv[x].modules.length:0; }
  var c1=document.getElementById('lvl-cnt-L1');
  var c2e=document.getElementById('lvl-cnt-L2');
  var c3=document.getElementById('lvl-cnt-L3');
  if(c1) c1.textContent='（'+cnt('L1')+' 個模組）';
  if(c2e) c2e.textContent='（'+cnt('L2')+' 個模組）';
  if(c3) c3.textContent='（'+cnt('L3')+' 個模組）';
}
function wtBackToStep1(){
  var s1=document.getElementById('wt-step1');
  var s1b=document.getElementById('wt-step1b');
  if(s1b) s1b.style.display='none';
  if(s1) s1.style.display='block';
}
var _wtPendingEnabled=[], _wtPendingToHide=[];
var ALL_MOD_LABELS_SHORT={
  dashboard:'儀表板',monitor:'全域監控',vol_hub:'人力中心',
  sorting:'物資整理站',warehouse:'物資倉儲',persons:'個案陪伴',
  shelter_mgt:'安置收容',assets:'資產調度',rtsync:'即時調度',
  line_oa:'Line OA',drive:'照片回報',admin:'系統管理'
};
function wtPickLevel(level){
  _wtPendingLevel=level;
  var def=WAR_MODULE_DEFAULTS[_wtPendingScenario]||WAR_MODULE_DEFAULTS['quake'];
  // L1/L2/L3：顯示模組預覽摘要，等待確認後再啟動
  if(level!=='manual'){
    var lvObj=(def.levels&&def.levels[level])?def.levels[level]:def.levels.L1;
    var enabled=lvObj.modules.slice();
    if(enabled.indexOf('dashboard')<0) enabled.unshift('dashboard');
    var ALL=['dashboard','monitor','vol_hub','sorting','warehouse','persons','shelter_mgt','assets','rtsync','line_oa','drive','admin'];
    var toHide=[];
    for(var i=0;i<ALL.length;i++){ if(enabled.indexOf(ALL[i])<0) toHide.push(ALL[i]); }
    _wtPendingEnabled=enabled; _wtPendingToHide=toHide;
    // 顯示預覽摘要
    var openNames=enabled.filter(function(m){return m!=='dashboard';}).map(function(m){return ALL_MOD_LABELS_SHORT[m]||m;});
    var hideNames=toHide.map(function(m){return ALL_MOD_LABELS_SHORT[m]||m;});
    var preview=document.getElementById('wt-level-preview');
    var confirmWrap=document.getElementById('wt-level-confirm-wrap');
    if(preview){
      preview.innerHTML='<div style="margin-bottom:6px"><span style="color:#4ade80;font-weight:600">將開啟：</span>'+openNames.join('、')+'</div>'
        +'<div><span style="color:#f87171;font-weight:600">將隱藏：</span>'+(hideNames.length?hideNames.join('、'):'（無）')+'</div>';
      preview.style.display='block';
    }
    if(confirmWrap) confirmWrap.style.display='block';
    return;
  }
  // 全手動：進確認頁逐項勾選
  var s1b=document.getElementById('wt-step1b');
  var s2=document.getElementById('wt-step2');
  if(s1b) s1b.style.display='none';
  if(s2) s2.style.display='block';
  var title=document.getElementById('wt-s2-title');
  if(title) title.textContent=def.emoji+' '+def.label+' · 全手動 — 自訂開放模組';
  var preset=['dashboard'];
  var el=document.getElementById('wt-mod-checks'); if(!el) return;
  var ALL_MOD_LABELS={
    monitor:'🖥️ 全域監控',vol_hub:'🧑‍🤝‍🧑 志工人力中心',
    sorting:'🧰 物資整理站',warehouse:'📦 物資倉儲',
    persons:'🫂 個案全程陪伴',shelter_mgt:'🏕️ 安置收容',
    assets:'🛏 資產調度',rtsync:'⚡ 即時調度中台',line_oa:'💬 Line OA',
    drive:'📸 照片回報',admin:'🔧 系統管理'
  };
  var html='';
  var allKeys=Object.keys(ALL_MOD_LABELS);
  for(var i=0;i<allKeys.length;i++){
    var mid=allKeys[i];
    var lbl=ALL_MOD_LABELS[mid]||mid;
    html+='<label style="display:flex;align-items:center;gap:8px;padding:8px 12px;border-radius:8px;cursor:pointer;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1)" id="wtmod-wrap-'+mid+'" onclick="wtToggleMod(\''+mid+'\')">';
    html+='<input type="checkbox" id="wtmod-'+mid+'" style="accent-color:#6ee7b7;width:15px;height:15px" onclick="event.stopPropagation();wtToggleMod(\''+mid+'\')">';
    html+='<span style="font-size:12px;color:#e2e8f0">'+lbl+'</span></label>';
  }
  el.innerHTML=html;
}
function wtDoLaunchLevel(){
  var def=WAR_MODULE_DEFAULTS[_wtPendingScenario]||WAR_MODULE_DEFAULTS['quake'];
  var enabled=_wtPendingEnabled; var toHide=_wtPendingToHide;
  disabledModules.clear();
  for(var i=0;i<toHide.length;i++) disabledModules.add(toHide[i]);
  saveDisabledModules();
  selectScenario(_wtPendingScenario);
  closeOverlay();
  renderNav(); renderModuleManager();
  var cnt=enabled.length-1;
  var lvLabel={L1:'L1 輕度',L2:'L2 中度',L3:'L3 重度'}[_wtPendingLevel]||_wtPendingLevel;
  logSys('ok','戰時啟動：'+def.label+' · '+lvLabel+'，開放 '+cnt+' 個模組');
  startSession(def.label, _wtPendingLevel);
  toast('⚡ '+def.emoji+' '+def.label+' · '+lvLabel+' 啟動（'+cnt+' 模組）');
}
function wtToggleMod(mid){
  var cb=document.getElementById('wtmod-'+mid);
  var wrap=document.getElementById('wtmod-wrap-'+mid);
  if(!cb) return;
  cb.checked=!cb.checked;
  if(wrap){
    wrap.style.background=cb.checked?'rgba(99,179,137,.18)':'rgba(255,255,255,.06)';
    wrap.style.borderColor=cb.checked?'rgba(99,179,137,.4)':'rgba(255,255,255,.1)';
  }
}
function wtBackToLevel(){
  var s1b=document.getElementById('wt-step1b');
  var s2=document.getElementById('wt-step2');
  if(s2) s2.style.display='none';
  if(s1b) s1b.style.display='block';
}
function wtConfirmAndLaunch(){
  var def=WAR_MODULE_DEFAULTS[_wtPendingScenario]||WAR_MODULE_DEFAULTS['quake'];
  var lvlLabel={L1:'L1 輕度',L2:'L2 中度',L3:'L3 重度',manual:'全手動'}[_wtPendingLevel]||_wtPendingLevel||'';
  var msg='確定進入 '+def.label+' '+lvlLabel+' 戰時模式？此操作將鎖定平時資料。';
  if(!confirm(msg)) return;
  var ALL_IDS=['monitor','vol_hub','sorting','warehouse','persons','shelter_mgt','assets','rtsync','line_oa','drive','admin'];
  var enabled=['dashboard'];
  var toHide=[];
  for(var i=0;i<ALL_IDS.length;i++){
    var cb=document.getElementById('wtmod-'+ALL_IDS[i]);
    if(cb&&cb.checked) enabled.push(ALL_IDS[i]);
    else toHide.push(ALL_IDS[i]);
  }
  disabledModules.clear();
  for(var j=0;j<toHide.length;j++) disabledModules.add(toHide[j]);
  saveDisabledModules();
  // 更新預設記憶（寫回對應等級；全手動不覆寫預設）
  if(_wtPendingLevel&&_wtPendingLevel!=='manual'&&def.levels&&def.levels[_wtPendingLevel]){
    def.levels[_wtPendingLevel].modules=enabled;
    def.levels[_wtPendingLevel].hidden=toHide;
    saveWarModuleDefaults();
  }
  selectScenario(_wtPendingScenario);
  closeOverlay();
  renderNav();
  renderModuleManager();
  var cnt=enabled.length-1;
  var lvlLabel={L1:'L1 輕度',L2:'L2 中度',L3:'L3 重度',manual:'全手動'}[_wtPendingLevel]||'';
  logSys('ok','戰時模組套用：'+def.label+' · '+lvlLabel+'，開放 '+cnt+' 個模組，隱藏 '+toHide.length+' 個');
  startSession(def.label, _wtPendingLevel);
  toast('⚡ 戰時模式啟動：'+def.emoji+' '+def.label+' · '+lvlLabel+'（'+cnt+' 模組）');
}
function selectScenario(id){
  setScenario(id);
  logSys('warn','戰時災型已選定：'+(SCENARIOS[id]?SCENARIOS[id].name:id));
}
// 切回平時：還原所有模組
var _peacetimeModules=null;
function restoreAllModulesForPeace(){
  disabledModules.clear();
  saveDisabledModules();
  renderNav();
  renderModuleManager();
}
function cycleP(el){
  if(role!=='admin'&&role!=='it'){
    toast('⚠ 只有總控或 IT 志工可以調整全責規範');
    return;
  }
  var roleId=el.dataset.role;
  var modId=el.dataset.mod;
  var tab=el.dataset.tab;
  var curIdx=P_CYCLE.indexOf(el.textContent.trim());
  var nextVal=P_CYCLE[(curIdx+1)%P_CYCLE.length];
  var perms=(tab==='peacetime')?PERMS_PEACE:PERMS_WAR;
  if(!perms[roleId]) perms[roleId]={};
  perms[roleId][modId]=nextVal;
  renderPermMatrix();
  logSys('ok','【權限變更】'+roleId+' · '+modId+' → '+nextVal);
  toast('✅ 權限已切換至：'+nextVal+' ('+P_LABELS[nextVal]+')');
}
function saveAllPerms() {
  // In production this would POST to backend
  toast('💾 全責規範設定已儲存');
}

// ── API ROWS ──
var apiTimers={},apiLongFlags={};
var API_LP_MS=500;
function apiStartPress(e,i){
  if(e.type==='touchstart'&&e.cancelable) e.preventDefault();
  apiLongFlags[i]=false;
  apiTimers[i]=setTimeout(function(){apiLongFlags[i]=true;triggerSingleApiTest(i);},API_LP_MS);
}
function apiEndPress(e,i){
  clearTimeout(apiTimers[i]);
  if(!apiLongFlags[i]) toggleAPIEnabled(i);
}
function apiCancelPress(i){clearTimeout(apiTimers[i]);}
function toggleAPIEnabled(i){
  var api=API_ENDPOINTS[i];
  if(api.enabled===undefined) api.enabled=true;
  api.enabled=!api.enabled;
  renderAPIRows();
  logSys('info','【API狀態】'+api.name+' 已'+(api.enabled?'開啟':'關閉'));
  toast(api.name+' 已'+(api.enabled?'🟢 啟用':'⚫ 關閉'));
}
function triggerSingleApiTest(i){
  var api=API_ENDPOINTS[i];
  if(!api.enabled){toast('⚠ 請先開啟該 API 再測試');return;}
  if(navigator.vibrate) navigator.vibrate(50);
  var row=document.getElementById('api-row-'+i);
  if(!row) return;
  var btn=row.querySelector('.api-smart-btn');
  var dot=row.querySelector('.api-dot');
  var lbl=row.querySelector('.api-status-lbl');
  if(btn){btn.disabled=true;btn.textContent='⏳';}
  if(lbl){lbl.textContent='測試中';lbl.style.color='var(--blue)';lbl.style.background='var(--blue-bg)';}
  if(dot) dot.style.background='var(--blue)';
  setTimeout(function(){
    var fail=['cwa.gov.tw'].some(function(d){return api.url.includes(d);});
    api.status=fail?'err':'ok';
    renderAPIRows();
    logSys(fail?'err':'ok','單獨測試：'+api.name+' → '+(fail?'中斷':'正常'));
    toast(api.name+' 測試：'+(fail?'❌ 中斷':'✅ 正常'));
  },1000);
}
function renderAPIRows(){
  var wrap=document.getElementById('api-rows');
  if(!wrap) return;
  var sColor={ok:'var(--green)',warn:'var(--amber)',err:'var(--red)'};
  var sLabel={ok:'正常',warn:'警告',err:'中斷'};
  var html='';
  for(var i=0;i<API_ENDPOINTS.length;i++){
    var api=API_ENDPOINTS[i];
    if(api.enabled===undefined) api.enabled=true;
    var sc=api.enabled?sColor[api.status]:'var(--text4)';
    var sl=api.enabled?sLabel[api.status]:'已關閉';
    var op=api.enabled?'':'style="opacity:.55;transition:opacity .2s"';
    var bs=api.enabled
      ?'background:var(--green-bg);color:var(--green);border-color:var(--green-border)'
      :'background:var(--bg4);color:var(--text3);border-color:var(--border2)';
    var bt=api.enabled?'啟用中':'已關閉';
    html+='<div class="api-row" id="api-row-'+i+'" '+op+'>'
      +'<div class="api-dot" style="background:'+sc+';box-shadow:0 0 4px '+sc+'"></div>'
      +'<input class="api-name-inp" value="'+api.name+'" id="api-name-'+i+'" placeholder="API 名稱"'+(api.enabled?'':' disabled')+'>'
      +'<input class="api-url-inp" value="'+api.url+'" id="api-url-'+i+'" placeholder="https://..."'+(api.enabled?'':' disabled')+'>'
      +'<span class="api-status-lbl" style="font-size:9px;padding:2px 7px;border-radius:6px;font-family:monospace;font-weight:600;background:'+sc+'22;color:'+sc+';border:1px solid '+sc+'44;white-space:nowrap;margin-right:4px">'+sl+'</span>'
      +'<button type="button" class="api-smart-btn" style="font-size:11px;padding:4px 10px;border-radius:var(--r-sm);border:1px solid;cursor:pointer;font-weight:500;user-select:none;white-space:nowrap;transition:all .15s;'+bs+'" '
      +'onmousedown="apiStartPress(event,'+i+')" onmouseup="apiEndPress(event,'+i+')" '
      +'onmouseleave="apiCancelPress('+i+')" ontouchstart="apiStartPress(event,'+i+')" ontouchend="apiEndPress(event,'+i+')" '
      +'title="短按開關 | 長按測試">'+bt+'</button>'
      +'<div class="api-del" onclick="deleteAPI('+i+')">×</div>'
      +'</div>';
  }
  wrap.innerHTML=html;
}

function addAPI() {
  API_ENDPOINTS.push({id:'api-'+Date.now(), name:'新 API', url:'https://', status:'warn'});
  renderAPIRows();
}
function deleteAPI(i) {
  API_ENDPOINTS.splice(i,1);
  renderAPIRows();
  toast('🗑 API 端點已移除');
}
