function handleSyncClick(){
  if(syncHoldFired){syncHoldFired=false;return;}
  syncSheets();
}
function startSyncHold(e){
  if(e&&e.cancelable) e.preventDefault();
  syncHoldFired=false;
  syncHoldTimer=setTimeout(function(){
    syncHoldFired=true;
    if(syncActive){
      syncActive=false;
      if(syncTimer){clearInterval(syncTimer);syncTimer=null;}
      updateSyncBtn();
      toast('⏸ 自動更新已關閉');
      logSys('info','自動同步已停止');
    } else {
      showSyncModal();
    }
  },600);
}
function clearSyncHold(){
  if(syncHoldTimer){clearTimeout(syncHoldTimer);syncHoldTimer=null;}
}
function showSyncModal(){
  var rates=[{v:10000,l:'⚡ 10 秒（戰時緊急）'},{v:30000,l:'⏱ 30 秒（標準）'},{v:60000,l:'📅 1 分鐘'},{v:300000,l:'💤 5 分鐘（節能）'}];
  var opts=rates.map(function(r){
    return '<label style="display:flex;align-items:center;gap:10px;padding:8px 10px;border:1px solid var(--border);border-radius:var(--r-sm);cursor:pointer;margin-bottom:6px;background:var(--bg3)">'
      +'<input type="radio" name="sr" value="'+r.v+'"'+(refreshInterval===r.v?' checked':'')+' style="accent-color:var(--green)">'
      +'<span style="font-size:12px">'+r.l+'</span></label>';
  }).join('');
  document.getElementById('modal-title').innerHTML='⏱ 設定自動更新頻率';
  document.getElementById('modal-body').innerHTML=opts;
  document.getElementById('modal-detail').textContent='';
  var footer=document.getElementById('modal').querySelector('.btn');
  footer.textContent='✓ 開啟自動更新';
  footer.onclick=function(){
    var sel=document.querySelector('input[name="sr"]:checked');
    if(sel){
      syncActive=true;
      changeRefreshRate(parseInt(sel.value));
      updateSyncBtn();
      logSys('ok','自動同步已啟動，頻率 '+Math.round(refreshInterval/1000)+' 秒');
    }
    footer.textContent='關閉'; footer.onclick=closeModal;
    closeModal();
  };
  document.getElementById('modal').classList.add('show');
}
var syncTimer=null,refreshInterval=30000;
function updateSheetUrl(v){
  var id=v.trim();
  var m=id.match(/\/spreadsheets\/d\/([a-zA-Z0-9_-]+)/);
  if(m) id=m[1];
  if(!id) return;
  DATA.field.sheetUrl='https://docs.google.com/spreadsheets/d/'+id+'/gviz/tq?tqx=out:json';
  saveData();
  toast('✓ 試算表 ID 已更新');
}
function syncSheets(){
  var el=document.getElementById('field-sync-time');
  if(!DATA.field.sheetUrl||DATA.field.sheetUrl.includes('SHEET_ID')){
    if(el) el.textContent='⬤ 尚未設定試算表';
    return;
  }
  fetch(DATA.field.sheetUrl)
    .then(function(r){return r.text();})
    .then(function(t){
      var json=JSON.parse(t.replace(/^[^{]+/,'').replace(/[^}]+$/,''));
      var rows=json.table&&json.table.rows;
      if(!rows) return;
      var colIdx={A:0,B:1,C:2,D:3,E:4,F:5,G:6,H:7};
      for(var i=0;i<DATA.stats.length;i++){
        var st=DATA.stats[i];
        if(st.local) continue;
        var ci=colIdx[st.col]||0;
        var ri=(st.row||2)-1;
        if(rows[ri]&&rows[ri].c&&rows[ri].c[ci]&&rows[ri].c[ci].v!=null){
          DATA.stats[i].val=String(rows[ri].c[ci].v);
        }
      }
      renderStats();
      if(el) el.textContent='⬤ 同步於 '+new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
      logSys('ok','Sheets 同步完成，數據已更新');
    })
    .catch(function(e){
      if(el) el.textContent='⬤ 同步失敗';
      logSys('err','Sheets 同步失敗：'+e.message);
    });
}
function startSyncTimer(){
  if(syncTimer) clearInterval(syncTimer);
  syncTimer=setInterval(syncSheets,refreshInterval);
}
function changeRefreshRate(val){
  refreshInterval=parseInt(val)||30000;
  var sel=document.getElementById('cfg-refresh-rate');
  if(sel) sel.value=String(refreshInterval);
  startSyncTimer();
  updateSyncBtn();
  toast('⏱ 更新頻率已設為 '+Math.round(refreshInterval/1000)+' 秒');
}
function openFieldSettings(){ toast('⚙ 試算表設定（貼上 Google Sheets 網址即可串接）'); }


// ── COUNTDOWN HELPERS ──
function parseHHMM(str) {
  if(!str) return null;
  var parts = str.split(':');
  if(parts.length < 2) return null;
  var now = new Date();
  var d = new Date(now.getFullYear(), now.getMonth(), now.getDate(),
    parseInt(parts[0]), parseInt(parts[1]), 0, 0);
  return d;
}
function formatCountdown(endTimeStr) {
  var end = parseHHMM(endTimeStr);
  if(!end) return '—';
  var now = new Date();
  var diff = end - now;
  if(diff <= 0) return '<span style="color:var(--red);font-weight:700">已超時</span>';
  var h = Math.floor(diff/3600000);
  var m = Math.floor((diff%3600000)/60000);
  var s = Math.floor((diff%60000)/1000);
  var color = diff < 900000 ? 'var(--red)' : diff < 1800000 ? 'var(--amber)' : 'var(--green)';
  var txt = (h>0?h+'h ':'') + m + 'm ' + s + 's';
  return '<span style="color:'+color+';font-weight:700;font-family:monospace">'+txt+'</span>';
}
function formatReceivedDelay(created, received) {
  if(!received) return '<span style="color:var(--text4)">未確認</span>';
  var c = parseHHMM(created);
  var r = parseHHMM(received);
  if(!c||!r) return received;
  var diff = r - c;
  if(diff < 0) diff += 86400000;
  var m = Math.floor(diff/60000);
  var s = Math.floor((diff%60000)/1000);
  var delayColor = diff > 300000 ? 'var(--red)' : diff > 60000 ? 'var(--amber)' : 'var(--green)';
  return '<span style="color:'+delayColor+'">'+received+' <span style="font-size:9px">(+'+m+'m'+s+'s)</span></span>';
}
var countdownTimer = null;
var escalated = {};
function startCountdown() {
  if(countdownTimer) clearInterval(countdownTimer);
  countdownTimer = setInterval(function(){
    document.querySelectorAll('.task-countdown').forEach(function(el){
      var t = el.dataset.end;
      el.innerHTML = formatCountdown(t);
    });
    for(var i=0;i<DATA.tasks.items.length;i++){
      var tk=DATA.tasks.items[i];
      if(tk.status==='done'||escalated[tk.id]) continue;
      var end=parseHHMM(tk.endTime);
      if(end&&end-new Date()<=0){
        escalated[tk.id]=true;
        logSys('err','【超時升級】'+tk.id+' '+tk.title.substring(0,18)+'… 已逾期，自動推播提醒組長並通知總控');
        toast('🔴 '+tk.id+' 已超時，升級通知已發送');
      }
    }
  }, 1000);
}


// ── PERMISSION REQUEST SYSTEM ──
var pendingPerm = null;
function requestPerm(roleName, modName, fromP, toP, reason){
  pendingPerm = {roleName:roleName, modName:modName, fromP:fromP, toP:toP};
  var banner = document.getElementById('perm-banner');
  var body   = document.getElementById('perm-banner-body');
  body.innerHTML = '<strong>'+roleName+'</strong> 申請將「'+modName+'」操作權限由 '
    +'<strong>'+fromP+'</strong> 提升至 <strong>'+toP+'</strong>。'
    +(reason?'<br><span style="color:var(--amber)">💡 '+reason+'</span>':'');
  banner.classList.add('show');
  logSys('warn','提權請求：'+roleName+' 申請 '+modName+' '+fromP+' → '+toP);
}
var TEMP_GRANTS=[];
function approvePerm(isApprove){
  document.getElementById('perm-banner').classList.remove('show');
  if(!pendingPerm) return;
  if(isApprove){
    var targetRole='staff';
    var targetMod='vol_hub';
    var prevP=(PERMS_PEACE[targetRole]&&PERMS_PEACE[targetRole][targetMod])||'P1';
    var newP=pendingPerm.toP.split(' ')[0];
    if(!PERMS_PEACE[targetRole]) PERMS_PEACE[targetRole]={};
    PERMS_PEACE[targetRole][targetMod]=newP;
    var key='ROUTE-KEY-'+Date.now().toString(36).slice(-6).toUpperCase();
    var grant={role:targetRole,mod:targetMod,prevP:prevP,key:key,expires:Date.now()+30000};
    TEMP_GRANTS.push(grant);
    renderPermMatrix();
    logSys('ok','【總控核准】'+pendingPerm.roleName+' 提權至 '+newP+'，矩陣已即時生效（金鑰 '+key+'，30 秒後自動回收 — 演練加速）');
    toast('✅ 提權已核准並寫入矩陣，30 秒後自動回收');
    setTimeout(function(){
      var idx=TEMP_GRANTS.indexOf(grant);
      if(idx<0) return;
      TEMP_GRANTS.splice(idx,1);
      PERMS_PEACE[grant.role][grant.mod]=grant.prevP;
      renderPermMatrix();renderNav();
      logSys('warn','【自動回收】臨時金鑰 '+grant.key+' 已到期，'+grant.role+'·'+grant.mod+' 權限還原為 '+grant.prevP);
      toast('⏳ 臨時提權已到期自動回收');
    },30000);
  } else {
    logSys('info','【總控拒絕】'+pendingPerm.roleName+' 提權申請已駁回。');
    toast('⚪ 提權申請已拒絕');
  }
  pendingPerm = null;
}

// ── SYSLOG ──
var logEntries = [];
function logSys(level, msg){
  var time = new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit',second:'2-digit'});
  var colorMap = {ok:'slog-ok', warn:'slog-warn', err:'slog-err', info:'slog-info'};
  var prefix   = {ok:'✓', warn:'⚠', err:'✗', info:'ℹ'};
  logEntries.unshift({time:time, level:level, msg:msg});
  if(logEntries.length > 50) logEntries.pop();
  if(typeof telemetryLog==='function') telemetryLog(level,msg);
  var el = document.getElementById('syslog');
  if(!el) return;
  el.innerHTML = logEntries.map(function(e){
    return '<div class="syslog-entry"><span class="slog-time">'+e.time+'</span>'
      +'<span class="'+colorMap[e.level]+'">'+prefix[e.level]+'</span> '+e.msg+'</div>';
  }).join('');
}
