// ── SCENARIO CRUD ──
function openSimEdit(){
  if(!editMode) return;
  document.querySelectorAll('.inline-edit-panel.show').forEach(function(p){p.classList.remove('show');});
  buildSimEditPanel();
  document.getElementById('iep-w-sim').classList.add('show');
}
function buildSimEditPanel(){
  var f=document.getElementById('iep-sim-fields');
  if(!f) return;
  var html='';
  var keys=Object.keys(SCENARIOS);
  for(var i=0;i<keys.length;i++){
    var k=keys[i];
    var sc=SCENARIOS[k];
    var canDel=(keys.length>1);
    var delBtn=canDel
      ?('<button class="iep-item-del" onclick="deleteScenarioById('+JSON.stringify(k)+')" style="margin-left:6px;flex-shrink:0">&times;</button>')
      :'<div style="width:30px"></div>';
    html+='<div class="iep-item-row" style="margin-bottom:10px;align-items:center;gap:6px">'
      // emoji display box + hidden input
      +'<div id="se-icon-box-'+k+'" style="width:38px;height:38px;border-radius:var(--r-sm);background:var(--bg3);border:1px solid var(--border2);display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;cursor:default">'+sc.emoji+'</div>'
      +'<input type="hidden" id="se-emoji-'+k+'" value="'+sc.emoji+'">'
      // AI button
      +'<button class="btn btn-ghost" id="se-ai-btn-'+k+'" onclick="aiGenIcon('+JSON.stringify(k)+')" style="padding:4px 8px;font-size:10px;flex-shrink:0;border-color:var(--purple-border);color:var(--purple)" title="AI 建議 Icon">✨</button>'
      // name + sub
      +'<input class="iep-inp" style="flex:1;margin:0;padding:6px 8px" id="se-name-'+k+'" placeholder="情境名稱" value="'+sc.name+'">'
      +'<input class="iep-inp" style="flex:2;margin:0;padding:6px 8px" id="se-sub-'+k+'" placeholder="說明文字" value="'+sc.sub+'">'
      +delBtn
      +'</div>';
  }
  f.innerHTML=html;
}

function aiGenIcon(k){
  var nameEl=document.getElementById('se-name-'+k);
  var subEl=document.getElementById('se-sub-'+k);
  var btn=document.getElementById('se-ai-btn-'+k);
  var box=document.getElementById('se-icon-box-'+k);
  var inp=document.getElementById('se-emoji-'+k);
  if(!nameEl) return;
  var name=nameEl.value.trim();
  var sub=subEl?subEl.value.trim():'';
  btn.textContent='⏳'; btn.disabled=true; box.textContent='…';
  setTimeout(function(){
    var combined=(name+sub).toLowerCase();
    var emoji='⚠️';
    if(combined.includes('物資')||combined.includes('糧')||combined.includes('補給')||combined.includes('便當')) emoji='📦';
    else if(combined.includes('風')||combined.includes('颱')) emoji='🌀';
    else if(combined.includes('水災')||combined.includes('淹')||combined.includes('洪')||combined.includes('雨')) emoji='🌊';
    else if(combined.includes('火')||combined.includes('爆')||combined.includes('燃')||combined.includes('炸')) emoji='🔥';
    else if(combined.includes('震')||combined.includes('塌')||combined.includes('垮')||combined.includes('地動')) emoji='🏚️';
    else if(combined.includes('醫')||combined.includes('病')||combined.includes('藥')||combined.includes('護')) emoji='🏥';
    else if(combined.includes('戰')||combined.includes('亂')||combined.includes('軍')||combined.includes('動亂')) emoji='⚔️';
    else if(combined.includes('人')||combined.includes('志工')||combined.includes('隊')||combined.includes('組')) emoji='👥';
    box.textContent=emoji; inp.value=emoji;
    btn.textContent='✨'; btn.disabled=false;
    toast('🤖 AI 語意分析成功，已自動匹配最佳 Icon：'+emoji);
  }, 600);
}

function deleteScenarioById(sid){
  if(Object.keys(SCENARIOS).length<=1){toast('⚠ 至少保留一個情境');return;}
  delete SCENARIOS[sid];
  if(currentScenario===sid) currentScenario=Object.keys(SCENARIOS)[0];
  buildSimEditPanel();
  toast('已移除情境');
}
function addScenario(){
  var newId='sc_'+Date.now();
  var base=SCENARIOS['quake']||SCENARIOS[Object.keys(SCENARIOS)[0]];
  SCENARIOS[newId]={
    name:'自訂新情境',emoji:'⚠️',sub:'請填寫演練說明',
    stats:JSON.parse(JSON.stringify(base.stats)),
    bugs:[]
  };
  buildSimEditPanel();
}
function saveSimEdit(){
  var keys=Object.keys(SCENARIOS);
  for(var i=0;i<keys.length;i++){
    var k=keys[i];
    var eEl=document.getElementById('se-emoji-'+k);
    var nEl=document.getElementById('se-name-'+k);
    var sEl=document.getElementById('se-sub-'+k);
    if(eEl) SCENARIOS[k].emoji=eEl.value;
    if(nEl) SCENARIOS[k].name=nEl.value;
    if(sEl) SCENARIOS[k].sub=sEl.value;
  }
  var simBtns=document.querySelector('.sim-btns');
  if(simBtns){
    var bhtml='';
    var ks=Object.keys(SCENARIOS);
    for(var j=0;j<ks.length;j++){
      var sc=SCENARIOS[ks[j]];
      var selCls=(currentScenario===ks[j]?' sel':'');
      bhtml+='<button class="sim-btn '+ks[j]+selCls+'" onclick="setScenario(\''+ks[j]+'\')">'
        +'<span class="sico">'+sc.emoji+'</span>'
        +'<div><div>'+sc.name+'</div><span class="ssub">'+ks[j]+'</span></div>'
        +'</button>';
    }
    simBtns.innerHTML=bhtml;
  }
  closeEdit('w-sim');
  toast('✓ 情境設定已儲存');
}


// ── PERSIST DATA to localStorage ──
var DATA_KEYS = ['stats','disaster','map','alerts','manpower','ai','warehouse','tasks','persons','shelter_mgt','registry','devTasks','relief_req','coord'];
function saveData(){
  var payload = {};
  for(var i=0;i<DATA_KEYS.length;i++) payload[DATA_KEYS[i]] = DATA[DATA_KEYS[i]];
  try{
    // 寫入前先把「目前版本」推入備份輪替（雙檔：backup_1 為前一版、backup_2 為前兩版）
    var prev = localStorage.getItem('drms_data');
    if(prev){
      var prevVer = localStorage.getItem('drms_version') || '0';
      var prevTime = localStorage.getItem('drms_version_time') || '';
      // backup_1 → backup_2（往後推一格）
      var b1 = localStorage.getItem('drms_backup_1');
      if(b1) localStorage.setItem('drms_backup_2', b1);
      // 目前版本 → backup_1
      localStorage.setItem('drms_backup_1', JSON.stringify({ver:prevVer,time:prevTime,data:prev}));
    }
    // 遞增版本流水號
    var ver = parseInt(localStorage.getItem('drms_version')||'0',10) + 1;
    localStorage.setItem('drms_version', String(ver));
    localStorage.setItem('drms_version_time', new Date().toLocaleString('zh-TW'));
    localStorage.setItem('drms_data', JSON.stringify(payload));
    snapshotBySlot(payload);
  }catch(e){
    logSys('err','localStorage 寫入失敗（容量/隱私模式），資料僅存於記憶體');
  }
}
// ── 時段備份系統（每日三槽：AM 10:00-15:00 / PM 15:01-20:00 / NIGHT 20:01-次日10:00，含空檔歸夜段）──
// 每個時段只保留「進入該時段後第一次存檔」的快照（即流量0%那一版），同時段後續存檔不覆蓋。
function _currentSlot(){
  var now=new Date();
  var m=now.getHours()*60+now.getMinutes();
  if(m>=600 && m<=900) return 'AM';        // 10:00 ~ 15:00
  if(m>=901 && m<=1200) return 'PM';       // 15:01 ~ 20:00
  return 'NIGHT';                          // 20:01 ~ 次日 09:59（含空檔）
}
function _slotKey(slot){ return 'drms_slot_'+slot; }
function _today(){ var d=new Date(); return d.getFullYear()+'-'+(d.getMonth()+1)+'-'+d.getDate(); }
function snapshotBySlot(payload){
  try{
    var slot=_currentSlot();
    var key=_slotKey(slot);
    var today=_today();
    var existing=null;
    try{ existing=JSON.parse(localStorage.getItem(key)||'null'); }catch(e){}
    // 該槽為空 或 槽內日期非今日 → 寫入此快照（時段起點 / 跨日覆蓋舊日）；否則保留起點不覆蓋
    if(!existing || existing.date!==today){
      var snap={
        date:today,
        slot:slot,
        ver:localStorage.getItem('drms_version')||'0',
        time:localStorage.getItem('drms_version_time')||new Date().toLocaleString('zh-TW'),
        data:JSON.stringify(payload)
      };
      localStorage.setItem(key, JSON.stringify(snap));
      logSys('ok','【時段備份】已建立 '+slot+' 時段起點快照 v'+snap.ver);
    }
  }catch(e){}
}
function getSlotInfo(){
  function rd(slot){ try{ return JSON.parse(localStorage.getItem(_slotKey(slot))||'null'); }catch(e){ return null; } }
  return { AM:rd('AM'), PM:rd('PM'), NIGHT:rd('NIGHT') };
}
function restoreSlot(slot){
  var info=getSlotInfo();
  var bk=info[slot];
  if(!bk||!bk.data){ toast('此時段無備份資料'); return; }
  var label={AM:'上午 10:00-15:00',PM:'下午 15:01-20:00',NIGHT:'夜間 20:01-次日10:00'}[slot]||slot;
  if(!confirm('確認還原至「'+label+'」時段起點（'+bk.date+' v'+bk.ver+'）？\n目前狀態會先自動備份至版本還原點，可再退回。')) return;
  // 還原前先把目前狀態推入版本備份輪替（讓還原本身可逆）
  var cur=localStorage.getItem('drms_data');
  if(cur){
    var b1=localStorage.getItem('drms_backup_1');
    if(b1) localStorage.setItem('drms_backup_2', b1);
    localStorage.setItem('drms_backup_1', JSON.stringify({ver:localStorage.getItem('drms_version')||'0',time:localStorage.getItem('drms_version_time')||'',data:cur}));
  }
  localStorage.setItem('drms_data', bk.data);
  var nv=parseInt(localStorage.getItem('drms_version')||'0',10)+1;
  localStorage.setItem('drms_version', String(nv));
  localStorage.setItem('drms_version_time', new Date().toLocaleString('zh-TW')+'（還原自'+slot+'時段 v'+bk.ver+'）');
  logSys('ok','已還原至 '+slot+' 時段起點 v'+bk.ver+'，並建立新版本 v'+nv);
  toast('↺ 已還原至'+label+'時段起點，重新載入中…');
  setTimeout(function(){ location.reload(); }, 800);
}
// ── 手動環形三槽備份（drms_manual_1/2/3，1 為最新，滿則擠掉最舊）──
function manualBackup(){
  var payload={};
  for(var i=0;i<DATA_KEYS.length;i++) payload[DATA_KEYS[i]]=DATA[DATA_KEYS[i]];
  var s2=localStorage.getItem('drms_manual_2');
  if(s2) localStorage.setItem('drms_manual_3', s2);
  var s1=localStorage.getItem('drms_manual_1');
  if(s1) localStorage.setItem('drms_manual_2', s1);
  var snap={ver:localStorage.getItem('drms_version')||'0',time:new Date().toLocaleString('zh-TW'),data:JSON.stringify(payload)};
  localStorage.setItem('drms_manual_1', JSON.stringify(snap));
  logSys('ok','【手動備份】已建立手動備份點 v'+snap.ver);
  toast('💾 已手動備份目前版本 v'+snap.ver);
  renderVersionPanel();
}
function getManualInfo(){
  function rd(n){ try{ return JSON.parse(localStorage.getItem('drms_manual_'+n)||'null'); }catch(e){ return null; } }
  return [rd(1),rd(2),rd(3)];
}
function restoreManual(n){
  var arr=getManualInfo();
  var bk=arr[n-1];
  if(!bk||!bk.data){ toast('此備份點無資料'); return; }
  if(!confirm('確認還原至手動備份 v'+bk.ver+'（'+bk.time+'）？\n目前狀態會先自動備份至版本還原點，可再退回。')) return;
  var cur=localStorage.getItem('drms_data');
  if(cur){
    var b1=localStorage.getItem('drms_backup_1');
    if(b1) localStorage.setItem('drms_backup_2', b1);
    localStorage.setItem('drms_backup_1', JSON.stringify({ver:localStorage.getItem('drms_version')||'0',time:localStorage.getItem('drms_version_time')||'',data:cur}));
  }
  localStorage.setItem('drms_data', bk.data);
  var nv=parseInt(localStorage.getItem('drms_version')||'0',10)+1;
  localStorage.setItem('drms_version', String(nv));
  localStorage.setItem('drms_version_time', new Date().toLocaleString('zh-TW')+'（還原自手動備份 v'+bk.ver+'）');
  logSys('ok','已還原至手動備份 v'+bk.ver+'，並建立新版本 v'+nv);
  toast('↺ 已還原至手動備份 v'+bk.ver+'，重新載入中…');
  setTimeout(function(){ location.reload(); }, 800);
}
// ── 版本還原系統 ──
function getVersionInfo(){
  return {
    current:{ver:localStorage.getItem('drms_version')||'0', time:localStorage.getItem('drms_version_time')||'—'},
    backup1:_parseBackup(localStorage.getItem('drms_backup_1')),
    backup2:_parseBackup(localStorage.getItem('drms_backup_2'))
  };
}
function _parseBackup(raw){
  if(!raw) return null;
  try{ var o=JSON.parse(raw); return {ver:o.ver,time:o.time,data:o.data}; }catch(e){ return null; }
}
function restoreVersion(slot){
  var info=getVersionInfo();
  var bk=(slot==='1')?info.backup1:info.backup2;
  if(!bk||!bk.data){ toast('此還原點無備份資料'); return; }
  if(!confirm('確認還原至版本 v'+bk.ver+'（'+bk.time+'）？\n目前未儲存的變更將被覆蓋，但會自動先備份目前狀態。')) return;
  // 還原前先把目前狀態備份（讓還原本身也可逆）
  var cur=localStorage.getItem('drms_data');
  if(cur){
    var curVer=localStorage.getItem('drms_version')||'0';
    var curTime=localStorage.getItem('drms_version_time')||'';
    var b1=localStorage.getItem('drms_backup_1');
    if(b1) localStorage.setItem('drms_backup_2', b1);
    localStorage.setItem('drms_backup_1', JSON.stringify({ver:curVer,time:curTime,data:cur}));
  }
  // 套用備份資料
  localStorage.setItem('drms_data', bk.data);
  var newVer=parseInt(localStorage.getItem('drms_version')||'0',10)+1;
  localStorage.setItem('drms_version', String(newVer));
  localStorage.setItem('drms_version_time', new Date().toLocaleString('zh-TW')+'（還原自 v'+bk.ver+'）');
  logSys('ok','已還原至版本 v'+bk.ver+'，並建立新版本 v'+newVer);
  toast('↺ 已還原至 v'+bk.ver+'，重新載入中…');
  setTimeout(function(){ location.reload(); }, 800);
}
function exportBackupFile(){
  // 匯出目前版本為 JSON 檔（離線備份）
  var payload={};
  for(var i=0;i<DATA_KEYS.length;i++) payload[DATA_KEYS[i]]=DATA[DATA_KEYS[i]];
  var snap={ver:localStorage.getItem('drms_version')||'0',time:new Date().toLocaleString('zh-TW'),data:payload};
  var blob=new Blob([JSON.stringify(snap,null,2)],{type:'application/json'});
  var url=URL.createObjectURL(blob);
  var a=document.createElement('a');
  a.href=url; a.download='DRMS_備份_v'+snap.ver+'_'+new Date().toISOString().slice(0,10)+'.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
  toast('📤 已匯出版本 v'+snap.ver+' 備份檔');
}
function importBackupFile(input){
  var file=input.files[0]; if(!file) return;
  var reader=new FileReader();
  reader.onload=function(e){
    try{
      var snap=JSON.parse(e.target.result);
      if(!snap.data){ toast('檔案格式不符'); return; }
      if(!confirm('確認從檔案還原版本 v'+(snap.ver||'?')+'（'+(snap.time||'')+'）？目前狀態會先自動備份。')) return;
      var cur=localStorage.getItem('drms_data');
      if(cur){
        var b1=localStorage.getItem('drms_backup_1');
        if(b1) localStorage.setItem('drms_backup_2', b1);
        localStorage.setItem('drms_backup_1', JSON.stringify({ver:localStorage.getItem('drms_version')||'0',time:localStorage.getItem('drms_version_time')||'',data:cur}));
      }
      localStorage.setItem('drms_data', JSON.stringify(snap.data));
      var nv=parseInt(localStorage.getItem('drms_version')||'0',10)+1;
      localStorage.setItem('drms_version', String(nv));
      localStorage.setItem('drms_version_time', new Date().toLocaleString('zh-TW')+'（匯入自檔案 v'+(snap.ver||'?')+'）');
      toast('↺ 已從檔案還原，重新載入中…');
      setTimeout(function(){ location.reload(); }, 800);
    }catch(err){ toast('檔案解析失敗'); }
  };
  reader.readAsText(file);
}
function renderVersionPanel(){
  var el=document.getElementById('version-panel'); if(!el) return;
  var info=getVersionInfo();
  var html='<div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;flex-wrap:wrap">';
  html+='<div style="background:var(--green-bg);border:1px solid var(--green-border);border-radius:var(--r-sm);padding:8px 14px">';
  html+='<div style="font-size:9px;color:var(--text4);font-weight:700;letter-spacing:.05em">目前版本</div>';
  html+='<div style="font-size:18px;font-weight:800;color:var(--green);font-family:monospace">v'+info.current.ver+'</div>';
  html+='<div style="font-size:10px;color:var(--text3)">'+info.current.time+'</div></div>';
  html+='<div style="font-size:11px;color:var(--text4);flex:1;min-width:160px">每次資料變更自動遞增版本並備份前兩版。若被誤觸改動，可一鍵還原。</div>';
  html+='</div>';
  // 還原點
  html+='<div style="display:grid;gap:8px">';
  var slots=[['1',info.backup1,'前一版'],['2',info.backup2,'前兩版']];
  for(var i=0;i<slots.length;i++){
    var s=slots[i], bk=s[1];
    html+='<div style="display:flex;align-items:center;gap:10px;padding:10px 14px;border:1px solid var(--border);border-radius:var(--r-sm);background:var(--bg2)">';
    html+='<div style="flex:1">';
    if(bk){
      html+='<div style="font-size:12px;font-weight:600">🕐 還原點 · '+s[2]+' <span style="font-family:monospace;color:var(--text3)">v'+bk.ver+'</span></div>';
      html+='<div style="font-size:10px;color:var(--text4)">'+bk.time+'</div>';
    } else {
      html+='<div style="font-size:12px;color:var(--text4)">🕐 還原點 · '+s[2]+'（尚無備份）</div>';
    }
    html+='</div>';
    if(bk) html+='<button class="btn btn-ghost btn-xs" onclick="restoreVersion(\''+s[0]+'\')">↺ 還原此版本</button>';
    html+='</div>';
  }
  html+='</div>';
  // 時段制三槽備份（每日 AM/PM/NIGHT，保留各時段起點）
  var si=getSlotInfo();
  var sNow=_currentSlot();
  html+='<div style="margin-top:16px;padding-top:14px;border-top:1px solid var(--border)">';
  html+='<div style="font-size:12px;font-weight:700;margin-bottom:8px">📅 每日時段備份 <span style="font-size:10px;color:var(--text4);font-weight:400">每段保留進入該時段的起點版本，跨日自動覆蓋</span></div>';
  html+='<div style="display:grid;gap:8px">';
  var ss=[['AM','上午段','10:00–15:00',si.AM],['PM','下午段','15:01–20:00',si.PM],['NIGHT','夜間段','20:01–次日10:00',si.NIGHT]];
  for(var j=0;j<ss.length;j++){
    var k=ss[j], bk=k[3], isNow=(k[0]===sNow);
    html+='<div style="display:flex;align-items:center;gap:10px;padding:10px 14px;border:1px solid '+(isNow?'var(--green-border)':'var(--border)')+';border-radius:var(--r-sm);background:var(--bg2)">';
    html+='<div style="flex:1">';
    html+='<div style="font-size:12px;font-weight:600">'+(isNow?'🟢':'🕐')+' '+k[1]+' <span style="font-size:10px;color:var(--text4);font-weight:400">'+k[2]+'</span>'+(isNow?' <span style="font-size:9px;color:var(--green)">當前時段</span>':'')+'</div>';
    if(bk){ html+='<div style="font-size:10px;color:var(--text4)">'+bk.date+' · 起點 v'+bk.ver+' · '+bk.time+'</div>'; }
    else { html+='<div style="font-size:10px;color:var(--text4)">尚無備份</div>'; }
    html+='</div>';
    if(bk) html+='<button class="btn btn-ghost btn-xs" onclick="restoreSlot(\''+k[0]+'\')">↺ 還原此時段</button>';
    html+='</div>';
  }
  html+='</div></div>';
  // 手動備份 / 還原（環形三槽，最多保留過去三版）
  var mi=getManualInfo();
  html+='<div style="margin-top:16px;padding-top:14px;border-top:1px solid var(--border)">';
  html+='<div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:8px;flex-wrap:wrap">';
  html+='<div style="font-size:12px;font-weight:700">💾 手動備份 <span style="font-size:10px;color:var(--text4);font-weight:400">手動建立還原點，最多保留過去三版</span></div>';
  html+='<button class="btn btn-green btn-xs" onclick="manualBackup()">💾 立即備份目前版本</button>';
  html+='</div>';
  html+='<div style="display:grid;gap:8px">';
  var hasAny=false;
  for(var mz=0;mz<3;mz++){
    var mbk=mi[mz];
    if(!mbk) continue;
    hasAny=true;
    html+='<div style="display:flex;align-items:center;gap:10px;padding:10px 14px;border:1px solid var(--border);border-radius:var(--r-sm);background:var(--bg2)">';
    html+='<div style="flex:1">';
    html+='<div style="font-size:12px;font-weight:600">↺ 手動備份點 '+(mz+1)+(mz===0?' <span style="font-size:9px;color:var(--green)">最新</span>':'')+' <span style="font-family:monospace;color:var(--text3)">v'+mbk.ver+'</span></div>';
    html+='<div style="font-size:10px;color:var(--text4)">'+mbk.time+'</div>';
    html+='</div>';
    html+='<button class="btn btn-ghost btn-xs" onclick="restoreManual('+(mz+1)+')">↺ 還原此版本</button>';
    html+='</div>';
  }
  if(!hasAny) html+='<div style="font-size:11px;color:var(--text4);padding:8px 0">尚無手動備份。點「立即備份目前版本」建立還原點。</div>';
  html+='</div></div>';
  // 離線備份匯出/匯入
  html+='<div style="display:flex;gap:8px;margin-top:14px;padding-top:14px;border-top:1px solid var(--border);flex-wrap:wrap">';
  html+='<button class="btn btn-blue btn-xs" onclick="exportBackupFile()">📤 匯出備份檔</button>';
  html+='<label class="btn btn-ghost btn-xs" style="cursor:pointer;margin:0">📥 從檔案還原<input type="file" accept="application/json" onchange="importBackupFile(this)" style="display:none"></label>';
  html+='</div>';
  el.innerHTML=html;
}
function loadNavOrder(){
  var raw=localStorage.getItem('drms_nav_order');
  if(raw){
    try{
      var order=JSON.parse(raw);
      NAV_CFG.sort(function(a,b){
        var ia=order.indexOf(a.id), ib=order.indexOf(b.id);
        return (ia<0?999:ia)-(ib<0?999:ib);
      });
    }catch(e){}
  }
  var dm=localStorage.getItem('drms_disabled_modules');
  if(dm){
    try{ JSON.parse(dm).forEach(function(id){disabledModules.add(id);}); }catch(e){}
  }
  var nc=localStorage.getItem('drms_nav_collapsed');
  if(nc==='1'&&window.innerWidth>768) document.body.classList.add('nav-collapsed');
}
function saveDisabledModules(){
  localStorage.setItem('drms_disabled_modules',JSON.stringify(Array.prototype.slice.call(disabledModules)));
}
function toggleModule(id){
  if(disabledModules.has(id)){ disabledModules.delete(id); }
  else { disabledModules.add(id); }
  saveDisabledModules();
  renderNav();
  renderModuleManager();
  var item=NAV_CFG.find(function(x){return x.id===id;});
  logSys('info','【模組】'+(item?item.label:id)+(disabledModules.has(id)?' 已關閉（從選單隱藏）':' 已開啟'));
  if(disabledModules.has(id)&&activePage===id){ showPage('dashboard'); }
}
function renderModuleManager(){
  var el=document.getElementById('module-mgr-list'); if(!el) return;
  var v='';
  for(var i=0;i<NAV_CFG.length;i++){
    var m=NAV_CFG[i];
    if(m.id==='dashboard'||m.id==='admin'){ continue; }
    var off=disabledModules.has(m.id);
    v+='<div style="display:flex;align-items:center;gap:10px;padding:9px 12px;background:var(--bg2);border:1px solid '+(off?'var(--border)':'var(--green-border)')+';border-radius:var(--r-sm);margin-bottom:6px;opacity:'+(off?'.55':'1')+'">';
    v+='<span style="font-size:16px">'+m.icon+'</span>';
    v+='<div style="flex:1"><div style="font-size:12px;font-weight:600">'+m.label+'</div><div style="font-size:9px;color:var(--text4);font-family:monospace">'+m.id+'</div></div>';
    v+='<span class="badge badge-'+(off?'red':'green')+'" style="font-size:9px">'+(off?'已關閉':'啟用中')+'</span>';
    v+='<button class="btn '+(off?'btn-green':'btn-ghost')+' btn-xs" onclick="toggleModule(\''+m.id+'\')">'+(off?'開啟':'關閉')+'</button>';
    v+='</div>';
  }
  var offCount=0; disabledModules.forEach(function(){offCount++;});
  el.innerHTML='<div style="font-size:11px;color:var(--text4);margin-bottom:10px">啟用中 '+(NAV_CFG.length-2-offCount)+' · 已關閉 '+offCount+' （儀表板與功能後台無法關閉，設定自動儲存）</div>'+v;
  renderWarModuleSettings();
}
var _WMS_LEVEL='L1';
function wmsSetLevel(lv){ _WMS_LEVEL=lv; renderWarModuleSettings(); }
function renderWarModuleSettings(){
  var el=document.getElementById('war-module-settings'); if(!el) return;
  var ALL_MOD_LABELS={
    monitor:'🖥️ 全域監控',vol_hub:'🧑‍🤝‍🧑 志工人力中心',
    sorting:'🧰 物資整理站',warehouse:'📦 物資倉儲',
    persons:'🫂 個案全程陪伴',shelter_mgt:'🏕️ 安置收容',
    assets:'🛏 資產調度',rtsync:'⚡ 即時調度中台',line_oa:'💬 Line OA',
    drive:'📸 照片回報',admin:'🔧 系統管理'
  };
  var ALL_IDS=Object.keys(ALL_MOD_LABELS);
  var scens=['quake','wind','flood','fire','landslide','compound','drought','epidemic','tsunami','war_s'];
  var lv=_WMS_LEVEL;
  // 等級分頁
  var lvls=[['L1','L1 輕度','#3B82F6'],['L2','L2 中度','#F59E0B'],['L3','L3 重度','#EF4444']];
  var html='<div style="display:flex;gap:6px;margin-bottom:14px">';
  for(var li=0;li<lvls.length;li++){
    var on=(lvls[li][0]===lv);
    html+='<button class="btn btn-xs '+(on?'btn-blue':'btn-ghost')+'" onclick="wmsSetLevel(\''+lvls[li][0]+'\')">'+lvls[li][1]+'</button>';
  }
  html+='</div>';
  html+='<div style="font-size:11px;color:var(--text4);margin-bottom:14px">目前編輯 <b>'+lv+'</b> 等級：勾選 = 切入該災型該等級時預設<b>開放</b>。設定即時儲存。</div>';
  html+='<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:760px">';
  html+='<thead><tr><th style="text-align:left;padding:8px 10px;font-size:10px;color:var(--text3);background:var(--bg3);border-bottom:1px solid var(--border);position:sticky;left:0">模組</th>';
  for(var si=0;si<scens.length;si++){
    var sd=WAR_MODULE_DEFAULTS[scens[si]];
    html+='<th style="text-align:center;padding:8px 4px;font-size:11px;color:var(--text2);background:var(--bg3);border-bottom:1px solid var(--border)">'+sd.emoji+'<br><span style="font-size:8px;font-weight:400">'+sd.label+'</span></th>';
  }
  html+='</tr></thead><tbody>';
  for(var mi=0;mi<ALL_IDS.length;mi++){
    var mid=ALL_IDS[mi];
    html+='<tr><td style="padding:7px 10px;font-size:11px;border-bottom:1px solid var(--border);font-weight:500;position:sticky;left:0;background:var(--bg2)">'+ALL_MOD_LABELS[mid]+'</td>';
    for(var sj=0;sj<scens.length;sj++){
      var sid=scens[sj];
      var lvObj=WAR_MODULE_DEFAULTS[sid].levels[lv];
      var chk=(lvObj&&lvObj.modules.indexOf(mid)>=0);
      html+='<td style="text-align:center;border-bottom:1px solid var(--border);padding:4px">';
      html+='<input type="checkbox" '+(chk?'checked':'')+' onchange="wmsToggle(\''+sid+'\',\''+mid+'\',this.checked)" style="width:14px;height:14px;accent-color:var(--green);cursor:pointer">';
      html+='</td>';
    }
    html+='</tr>';
  }
  html+='</tbody></table></div>';
  html+='<div style="margin-top:12px;display:flex;gap:8px"><button class="btn btn-ghost btn-xs" onclick="wmsReset()">↺ 恢復系統預設</button><span style="font-size:11px;color:var(--text4);align-self:center">變更即時儲存，下次進戰時生效</span></div>';
  el.innerHTML=html;
}
var _WMS_FACTORY=JSON.parse(JSON.stringify(WAR_MODULE_DEFAULTS));
function wmsToggle(scen,mid,checked){
  var lvObj=WAR_MODULE_DEFAULTS[scen].levels[_WMS_LEVEL];
  if(!lvObj) return;
  var arr=lvObj.modules;
  var idx=arr.indexOf(mid);
  if(checked&&idx<0) arr.push(mid);
  else if(!checked&&idx>=0) arr.splice(idx,1);
  // 同步 hidden
  var ALL=['dashboard','monitor','vol_hub','sorting','warehouse','persons','shelter_mgt','assets','rtsync','line_oa','drive','admin'];
  lvObj.hidden=ALL.filter(function(x){return arr.indexOf(x)<0;});
  saveWarModuleDefaults();
}
function wmsReset(){
  for(var k in _WMS_FACTORY){
    if(WAR_MODULE_DEFAULTS[k]) WAR_MODULE_DEFAULTS[k].levels=JSON.parse(JSON.stringify(_WMS_FACTORY[k].levels));
  }
  saveWarModuleDefaults(); renderWarModuleSettings(); toast('↺ 已恢復系統預設');
}
// ── DEV TASKS (IT 待辦需求) ──────────────────────────────────
function renderDevTasks(){
  var list=document.getElementById('dt-list'); if(!list) return;
  var tasks=DATA.devTasks||[];
  var open=tasks.filter(function(t){return !t.done;}).length;
  var badge=document.getElementById('dt-badge');
  if(badge) badge.textContent=open+' 項待辦 / '+tasks.length+' 項總計';
  if(!tasks.length){list.innerHTML='<div style="padding:16px;text-align:center;color:var(--text4);font-size:12px">目前沒有待辦需求</div>';return;}
  var priLabel={hi:'高',md:'中',lo:'低'};
  list.innerHTML=tasks.map(function(t){
    return '<div class="dt-row'+(t.done?' dt-done':'')+'" id="dtr-'+t.id+'">'
      +'<input type="checkbox" class="dt-check" '+(t.done?'checked':'')+' onchange="toggleDTDone(\''+t.id+'\')" title="標記完成">'
      +'<div class="dt-pri '+t.pri+'">'+priLabel[t.pri]+'</div>'
      +'<div class="dt-body">'
        +'<div class="dt-title">'+escHtml(t.title)+'</div>'
        +'<div class="dt-meta">'
          +(t.mod?'<span class="dt-mod">'+escHtml(t.mod)+'</span>':'')
          +'<input class="inp dt-ass-inp" value="'+escHtml(t.assignee||'')+'" placeholder="指派給 IT 人員…" '
            +'style="width:130px;font-size:10px;padding:3px 7px;display:inline-block" '
            +'onchange="assignDT(\''+t.id+'\',this.value)" onblur="assignDT(\''+t.id+'\',this.value)">'
          +'<span style="font-size:10px;color:var(--text4);margin-left:auto">'+escHtml(t.created||'')+'</span>'
        +'</div>'
      +'</div>'
      +'<div class="dt-actions">'
        +'<div class="wt-btn wt-hide" style="font-size:11px" onclick="deleteDT(\''+t.id+'\')" title="刪除">×</div>'
      +'</div>'
    +'</div>';
  }).join('');
}
function escHtml(s){return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
function toggleDTForm(){
  var f=document.getElementById('dt-add-form');
  f.classList.toggle('show');
  if(f.classList.contains('show')) document.getElementById('dt-inp-title').focus();
}
function submitDTTask(){
  var title=(document.getElementById('dt-inp-title').value||'').trim();
  if(!title){toast('請填寫需求說明');return;}
  var tasks=DATA.devTasks||[];
  var now=new Date();
  var d=now.getFullYear()+'-'+(now.getMonth()+1+'').padStart(2,'0')+'-'+(now.getDate()+'').padStart(2,'0');
  tasks.push({
    id:'dt'+(Date.now()),
    pri:document.getElementById('dt-inp-pri').value||'md',
    mod:document.getElementById('dt-inp-mod').value||'',
    title:title,
    assignee:document.getElementById('dt-inp-ass').value||'',
    done:false,
    created:d
  });
  DATA.devTasks=tasks;
  saveData();
  document.getElementById('dt-inp-title').value='';
  document.getElementById('dt-inp-ass').value='';
  toggleDTForm();
  renderDevTasks();
  toast('✓ 需求已新增');
}
function toggleDTDone(id){
  var t=(DATA.devTasks||[]).find(function(x){return x.id===id;});
  if(t){t.done=!t.done;saveData();renderDevTasks();}
}
function assignDT(id,val){
  var t=(DATA.devTasks||[]).find(function(x){return x.id===id;});
  if(t&&t.assignee!==val){t.assignee=val;saveData();}
}
function deleteDT(id){
  DATA.devTasks=(DATA.devTasks||[]).filter(function(x){return x.id!==id;});
  saveData();renderDevTasks();
}

function loadData(){
  loadNavOrder();
  var raw = localStorage.getItem('drms_data');
  if(!raw) return;
  try{
    var saved = JSON.parse(raw);
    for(var i=0;i<DATA_KEYS.length;i++){
      if(saved[DATA_KEYS[i]]) DATA[DATA_KEYS[i]] = saved[DATA_KEYS[i]];
    }
  }catch(e){}
}
function resetAll(){
  if(!confirm('確認清除所有已儲存設定，恢復預設值？')) return;
  localStorage.removeItem('drms_config');
  localStorage.removeItem('drms_data');
  localStorage.removeItem('drms_nav_order');
  location.reload();
}


