var RES_TAB = 'warehouse';
function setResourcesTab(t){
  RES_TAB = t;
  ['warehouse','assets','sorting','coord','kitchen'].forEach(function(x){
    var b=document.getElementById('restab-'+x);
    if(b) b.className='btn '+(x===t?'btn-blue':'btn-ghost');
  });
  renderResources();
}
// 次層 tab bar：視覺上明顯區別於母層
function subTabBar(tabs, activeId){
  var bar='<div style="display:flex;gap:0;border-bottom:2px solid var(--border);margin-bottom:14px;background:transparent">';
  tabs.forEach(function(t){
    var active=t.id===activeId;
    bar+='<button id="'+t.btnId+'" onclick="'+t.fn+'" style="'
      +'background:none;border:none;cursor:pointer;padding:7px 14px;font-size:12px;font-weight:'+(active?'600':'400')+';'
      +'color:'+(active?'var(--blue)':'var(--text3)')+';'
      +'border-bottom:'+(active?'2px solid var(--blue)':'2px solid transparent')+';'
      +'margin-bottom:-2px;white-space:nowrap;transition:color .15s">'+t.label+'</button>';
  });
  return bar+'</div>';
}
function renderResources(){
  var el=document.getElementById('resources-content'); if(!el) return;
  if(RES_TAB==='warehouse'){
    el.innerHTML='<div id="res-wh"></div>';
    renderWarehouse('res-wh');
  } else if(RES_TAB==='assets'){
    el.innerHTML=subTabBar([
      {id:'overview',btnId:'atab-overview',label:'📋 資產總覽',fn:"setAssetTab('overview')"},
      {id:'loan',    btnId:'atab-loan',    label:'📤 前線調用',fn:"setAssetTab('loan')"},
      {id:'transit', btnId:'atab-transit', label:'🚚 運送追蹤',fn:"setAssetTab('transit')"},
      {id:'return',  btnId:'atab-return',  label:'↩️ 歸還盤點',fn:"setAssetTab('return')"},
    ], ASSET_TAB)+'<div id="res-assets"></div>';
    renderAssets('res-assets');
  } else if(RES_TAB==='sorting'){
    el.innerHTML=subTabBar([
      {id:'board',  btnId:'stab-board',  label:'📊 作業看板',  fn:"setSortTab('board')"},
      {id:'intake', btnId:'stab-intake', label:'📥 收件登記',  fn:"setSortTab('intake')"},
      {id:'sort',   btnId:'stab-sort',   label:'✂️ 拆箱分類台',fn:"setSortTab('sort')"},
      {id:'discard',btnId:'stab-discard',label:'🗑 報廢/覆核', fn:"setSortTab('discard')"},
    ], SORT_TAB)+'<div id="res-sorting"></div>';
    renderSorting('res-sorting');
  } else if(RES_TAB==='coord'){
    el.innerHTML=subTabBar([
      {id:'match',  btnId:'cotab-match',  label:'🔗 缺口媒合',fn:"setCoordTab('match')"},
      {id:'partner',btnId:'cotab-partner',label:'🏢 外部單位',fn:"setCoordTab('partner')"},
      {id:'zone',   btnId:'cotab-zone',   label:'📍 責任分區',fn:"setCoordTab('zone')"},
    ], COORD_TAB)+'<div id="res-coord"></div>';
    renderCoord('res-coord');
  } else if(RES_TAB==='kitchen'){
    el.innerHTML=renderKitchen();
  }
}
function renderKitchen(){
  var d=DATA.kitchen;
  var lowDays=d.supplies.filter(function(s){return s.days<4;});
  var alertHtml = lowDays.length
    ? '<div style="background:var(--red-bg);border:1px solid var(--red-border);border-radius:var(--r-sm);padding:8px 12px;font-size:11px;color:var(--red);margin-bottom:12px">⚠ 庫存低於4天：'+lowDays.map(function(s){return s.item+'（'+s.days.toFixed(1)+'天）';}).join('、')+'</div>'
    : '';
  var siteHtml = d.sites.map(function(s){
    return '<div class="card" style="margin-bottom:10px">'
      +'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">'
      +'<span style="font-weight:600">🍲 '+s.name+'</span>'
      +'<span class="badge '+(s.status==='供餐中'?'badge-green':'badge-amber')+'">'+s.status+'</span>'
      +'</div>'
      +'<div style="font-size:11px;color:var(--text3)">志工 '+s.staff+' 人｜今日供餐 <strong>'+s.mealsToday+'</strong> 份</div>'
      +'<div style="font-size:11px;color:var(--text4);margin-top:3px">今日菜色：'+s.menu+'</div>'
      +'</div>';
  }).join('');
  var supHtml='<table class="tbl"><thead><tr><th>食材</th><th>庫存</th><th>日耗</th><th>可用天數</th></tr></thead><tbody>';
  d.supplies.forEach(function(s){
    var urgent=s.days<4;
    supHtml+='<tr>'
      +'<td>'+s.item+'</td>'
      +'<td>'+s.stock+' '+s.unit+'</td>'
      +'<td>'+s.dailyUse+'</td>'
      +'<td style="font-weight:600;color:'+(urgent?'var(--red)':'var(--green)')+'">'+s.days.toFixed(1)+' 天'+(urgent?' ⚠':'')+'</td>'
      +'</tr>';
  });
  supHtml+='</tbody></table>';
  var logHtml='<table class="tbl"><thead><tr><th>時間</th><th>站點</th><th>供餐數</th><th>備注</th></tr></thead><tbody>'
    +d.mealLog.map(function(l){
      return '<tr><td class="sh-time">'+l.time+'</td><td>'+l.site+'</td><td>'+l.qty+'份</td><td style="font-size:11px;color:var(--text3)">'+l.note+'</td></tr>';
    }).join('')+'</tbody></table>';
  return alertHtml
    +'<div class="g2">'
    +'<div>'+siteHtml+'<button class="btn btn-amber" style="margin-top:6px;width:100%" onclick="toast(\'🍲 供餐數已登記（演練模擬）\')">＋ 登記供餐</button></div>'
    +'<div><div class="card" style="margin-bottom:12px"><div class="card-title">📦 食材庫存監控</div>'+supHtml+'</div>'
    +'<div class="card"><div class="card-title">📋 供餐紀錄</div>'+logHtml+'</div></div>'
    +'</div>';
}

