function renderMedicalCheckin(){
  var el=document.getElementById('medical-checkin-content'); if(!el) return;
  var d=DATA.medicalStaff;
  var checkedIn=d.roster.filter(function(m){return m.checkin;}).length;
  var statsHtml='<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:14px">'
    +['<div class="card" style="text-align:center"><div style="font-size:22px;font-weight:700;color:var(--blue)">'+d.roster.length+'</div><div style="font-size:10px;color:var(--text4)">醫護合計</div></div>',
      '<div class="card" style="text-align:center"><div style="font-size:22px;font-weight:700;color:var(--green)">'+checkedIn+'</div><div style="font-size:10px;color:var(--text4)">已報到</div></div>',
      '<div class="card" style="text-align:center"><div style="font-size:22px;font-weight:700;color:var(--amber)">'+(d.roster.length-checkedIn)+'</div><div style="font-size:10px;color:var(--text4)">未報到</div></div>',
    ].join('')+'</div>';
  var tbl='<table class="tbl"><thead><tr><th>ID</th><th>姓名</th><th>職別</th><th>執照</th><th>所屬單位</th><th>指派站點</th><th>報到</th><th>操作</th></tr></thead><tbody>'
    +d.roster.map(function(m){
      return '<tr>'
        +'<td class="sh-time">'+m.id+'</td>'
        +'<td style="font-weight:600">'+m.name+'</td>'
        +'<td><span class="badge badge-blue">'+m.role+'</span></td>'
        +'<td style="font-size:10px;font-family:monospace;color:var(--text4)">'+m.license+'</td>'
        +'<td style="font-size:11px">'+m.org+'</td>'
        +'<td style="font-size:11px">'+(m.station||'<span style="color:var(--text4)">未指派</span>')+'</td>'
        +'<td>'+(m.checkin?'<span class="badge badge-green">✓ '+m.checkinTime+'</span>':'<span class="badge badge-amber">待報到</span>')+'</td>'
        +'<td>'+(m.checkin?''
          :'<button class="btn btn-green btn-xs" onclick="medCheckin(\''+m.id+'\')">✅ 報到</button>')+'</td>'
        +'</tr>';
    }).join('')+'</tbody></table>';
  el.innerHTML=statsHtml+'<div class="card"><div class="card-title">🏥 醫護人員名冊</div>'+tbl
    +'<button class="btn btn-primary" style="margin-top:10px" onclick="addMedStaff()">＋ 登錄新醫護人員</button></div>';
}
function medCheckin(id){
  var m=DATA.medicalStaff.roster.find(function(x){return x.id===id;});
  if(!m) return;
  m.checkin=true;
  m.checkinTime=new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'});
  logSys('ok','【醫護報到】'+m.name+'（'+m.role+'）'+m.checkinTime);
  toast('✅ '+m.name+' 報到完成');
  renderMedicalCheckin();
}
function addMedStaff(){
  var name=prompt('姓名：'); if(!name) return;
  var role=prompt('職別（醫師/護理師/藥師/心理師）：')||'護理師';
  var license=prompt('執照號碼：')||'—';
  var org=prompt('所屬單位：')||'慈濟醫療';
  var newId='MD-S'+(DATA.medicalStaff.roster.length+1).toString().padStart(2,'0');
  DATA.medicalStaff.roster.push({id:newId,name:name,role:role,license:license,org:org,group:'醫護組',checkin:'',checkinTime:'',station:''});
  toast('✅ 醫護人員 '+name+' 已登錄');
  renderMedicalCheckin();
}

function renderWarehouse(targetId){
  var el=document.getElementById(targetId||'warehouse-content'); if(!el) return;
  var d=DATA.warehouse;
  var stColor={'配送中':'badge-blue','待命':'badge-amber','回程中':'badge-green'};
  var pC={P1:'var(--red)',P2:'var(--amber)',P3:'var(--green)'};
  var qC={'待派案':'badge-amber','已派案':'badge-blue','配送中':'badge-purple','已送達':'badge-green'};
  var qhtml='<div class="card" style="margin-bottom:14px"><div class="card-title"><span class="dot blink" style="background:var(--amber)"></span>供需派案台 — 前線 Line 需求單</div>'
    +'<table class="tbl"><thead><tr><th>急迫</th><th>單號</th><th>品項</th><th>送達</th><th>時限</th><th>狀態</th><th>操作</th></tr></thead><tbody>';
  var sorted=d.reqs.slice().sort(function(a,b){return a.prio.localeCompare(b.prio);});
  for(var qi=0;qi<sorted.length;qi++){
    var rq=sorted[qi];
    qhtml+='<tr>'
      +'<td><span style="font-weight:700;color:'+pC[rq.prio]+';font-family:monospace">'+rq.prio+'</span></td>'
      +'<td class="sh-time">'+rq.id+'</td>'
      +'<td style="font-weight:500">'+rq.item+' '+rq.qty+'</td>'
      +'<td style="font-size:11px">'+rq.site+'</td>'
      +'<td style="font-size:11px;color:'+((rq.due&&rq.due.includes('1 小時'))?'var(--red)':'var(--text3)')+'">'+( rq.due||'—')+'</td>'
      +'<td><span class="badge '+qC[rq.status]+'">'+rq.status+'</span>'+(rq.driver?'<div style="font-size:9px;color:var(--text4)">'+rq.driver+'</div>':'')+'</td>'
      +'<td>'+(rq.status==='待派案'?'<button class="btn btn-amber btn-xs" onclick="dispatchReq(\''+rq.id+'\')">🚛 派案</button>':'')+'</td>'
      +'</tr>';
  }
  qhtml+='</tbody></table></div>';
  var html=qhtml+'<div class="card"><div class="card-title">📦 '+d.title+'</div>'
    +'<div style="background:var(--green-bg);border:1px solid var(--green-border);border-radius:var(--r-sm);padding:9px 12px;font-size:11px;color:var(--green);font-weight:500;margin-bottom:12px">✓ '+d.classification+'</div>'
    +'<table class="tbl"><thead><tr><th>車輛</th><th>駕駛</th><th>物流動線</th><th>狀態</th></tr></thead><tbody>';
  for(var i=0;i<d.trucks.length;i++){
    var t=d.trucks[i];
    html+='<tr><td style="font-weight:600">🚛 '+t.truckId+'</td><td>'+t.driver+'</td>'
      +'<td style="font-size:11px;font-family:monospace">'+t.route+'</td>'
      +'<td><span class="badge '+(stColor[t.status]||'badge-blue')+'">'+t.status+'</span></td></tr>';
  }
  html+='</tbody></table>'
    +'<button class="btn btn-amber" style="margin-top:12px" onclick="toast(\'🚛 大車調度請求已送出（演練模擬）\')">＋ 申請大車調度</button></div>';
  el.innerHTML=html;
}
function renderShelterMgt(targetId){
  var el=document.getElementById(targetId||'shelter-mgt-content'); if(!el) return;
  var d=DATA.shelter_mgt;
  var modeBtns='';
  for(var i=0;i<d.modes.length;i++){
    var m=d.modes[i];
    var sel=(m===d.currentMode);
    modeBtns+='<button class="war-sub'+(sel?' sel':'')+'" onclick="switchShelterMode('+i+')">'+m+'</button>';
  }
  var html='<div class="card"><div class="card-title">🏕️ '+d.title+'</div>'
    +'<div class="war-sub-lbl">作業模式切換：</div>'
    +'<div class="dflex gap6 fwrap" style="margin-bottom:14px">'+modeBtns+'</div>'
    +'<table class="tbl"><thead><tr><th>編號</th><th>收容所</th><th>收容人數</th><th>慰問金</th><th>清修狀態</th><th>模式操作</th></tr></thead><tbody>';
  var rColor={'已發放應急金':'badge-green','審核中':'badge-amber'};
  var cColor={'清掃完成':'badge-green','待清掃':'badge-amber','修繕規劃中':'badge-blue'};
  for(var i=0;i<d.records.length;i++){
    var r=d.records[i];
    var act='';
    if(d.currentMode==='安心家訪模式') act='<button class="btn btn-blue btn-xs" onclick="shelterAct('+i+',\'visit\')">🏠 排家訪</button>';
    else if(d.currentMode==='應急慰問金發放模式') act=(r.reliefStatus==='審核中'?'<button class="btn btn-green btn-xs" onclick="shelterAct('+i+',\'relief\')">💰 核發</button>':'<span style="font-size:9px;color:var(--text4)">已核發</span>');
    else act=(r.cleanStatus!=='清掃完成'?'<button class="btn btn-amber btn-xs" onclick="shelterAct('+i+',\'clean\')">🧹 派工</button>':'<span style="font-size:9px;color:var(--text4)">已完成</span>');
    html+='<tr><td class="sh-time">'+r.id+'</td><td style="font-weight:500">'+r.shelter+'</td>'
      +'<td style="font-family:monospace">'+r.evacueeCount+' 人</td>'
      +'<td><span class="badge '+(rColor[r.reliefStatus]||'badge-blue')+'">'+r.reliefStatus+'</span></td>'
      +'<td><span class="badge '+(cColor[r.cleanStatus]||'badge-blue')+'">'+r.cleanStatus+'</span></td>'
      +'<td>'+act+'</td></tr>';
  }
  html+='</tbody></table></div>';
  el.innerHTML=html;
}
function recalcSupplyStat(){
  var reqs=DATA.warehouse.reqs;
  if(!reqs.length) return;
  var done=reqs.filter(function(x){return x.status==='已送達';}).length;
  var pct=Math.round(done/reqs.length*100);
  DATA.stats[4].val=pct+'%';
  DATA.stats[4].sub='派案 '+done+'/'+reqs.length+' 完成';
  renderStats();
}
function dispatchReq(rid){
  var rq=DATA.warehouse.reqs.find(function(x){return x.id===rid;});
  if(!rq||rq.status!=='待派案') return;
  var freeTruck=DATA.warehouse.trucks.find(function(t){return t.status==='待命';});
  if(!freeTruck){toast('⚠ 無可用車輛，'+rid+' 維持待派案');logSys('warn','派案失敗：無可用車輛');return;}
  rq.status='已派案';
  rq.driver=freeTruck.truckId+' '+freeTruck.driver;
  freeTruck.status='配送中';
  var src=rq.item.includes('醫療')?'本會醫材庫':'竹崎倉儲';
  freeTruck.route=src+' → '+rq.site;
  var itemName=rq.item.replace(/[^\u4e00-\u9fff]/g,'');
  var sup=DATA.field.supplies.find(function(x){return itemName.includes(x.item)||x.item.includes(itemName);});
  if(sup){
    var n=rq.qty.includes('100')?100:(rq.qty.includes('50')?50:10);
    sup.stock=Math.max(sup.stock-n,0);
    sup.status=sup.stock<sup.need*0.3?'red':(sup.stock<sup.need?'amber':'green');
    renderField();
    logSys('info','庫存扣減：'+sup.item+' -'+n+' → 剩 '+sup.stock+'，現場端已同步');
  }
  DATA.tasks.items.unshift({id:rid.replace('REQ','TD'),type:'logistics',icon:'🚛',
    title:'配送 — '+rq.item+rq.qty+' → '+rq.site,assign:rq.driver,status:'active',pct:30,
    created:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'}),
    received:new Date().toLocaleTimeString('zh-TW',{hour:'2-digit',minute:'2-digit'}),
    endTime:new Date(Date.now()+3600000).toTimeString().substring(0,5),lineNotified:true,
    desc:'派案台自動建立：'+rq.id+' '+rq.item+rq.qty+'，'+rq.due+'送達'+rq.site});
  renderTasks();recalcSupplyStat();saveData();
  renderWarehouse();renderNav();renderAlerts();
  logSys('ok','【派案】'+rid+' '+rq.item+rq.qty+' → '+rq.site+'，指派 '+rq.driver+'，配送任務卡已建立');
  toast('🚛 '+rid+' 已派案，司機 Line 已收到配送單');
  if(typeof loaHook==='function'){
    loaHook('driver','🚛 派送通知\n'+rq.item+rq.qty+'\n→ '+rq.site+'\n請於 '+rq.due+' 前送達');
    loaHook('staff','📦 叫料派案\n'+rid+' '+rq.item+rq.qty+'\n指派：'+rq.driver);
  }
  setTimeout(function(){
    if(rq.status!=='已派案') return;
    rq.status='配送中';
    renderWarehouse();
    logSys('info',rid+' 司機已取貨 → 配送中（ETA 18 分鐘）');
  },4000);
  setTimeout(function(){
    if(rq.status!=='配送中') return;
    rq.status='已送達';
    var tr=DATA.warehouse.trucks.find(function(t){return rq.driver.includes(t.truckId);});
    if(tr){tr.status='待命';tr.route='返回待命';}
    var dt=DATA.tasks.items.find(function(t){return t.id===rid.replace('REQ','TD');});
    if(dt){dt.status='done';dt.pct=100;renderTasks();}
    recalcSupplyStat();
    renderWarehouse();renderNav();renderAlerts();
    logSys('ok',rid+' ✓ 已送達 '+rq.site+'，需求端已收簽收通知，車輛釋回，任務卡已結案');
    toast('✅ '+rid+' 配送完成');
  },9000);
}
function shelterAct(i,kind){
  var r=DATA.shelter_mgt.records[i];
  if(kind==='relief'){
    r.reliefStatus='已發放應急金';
    logSys('ok','【慰問金】'+r.shelter+' 應急金核發完成，'+r.evacueeCount+' 人受惠，名冊已回寫');
    toast('💰 '+r.shelter+' 慰問金已核發');
  } else if(kind==='clean'){
    r.cleanStatus='清掃完成';
    var tid='T'+String(Date.now()).slice(-3);
    logSys('ok','【清修派工】'+r.shelter+' 清掃任務 '+tid+' 已派發環保站志工，Line 已推播');
    toast('🧹 '+r.shelter+' 清掃派工完成');
  } else {
    logSys('info','【家訪】'+r.shelter+' 周邊已排入安心家訪動線，中樞神經金鑰流程啟動');
    toast('🏠 '+r.shelter+' 已排入家訪動線');
  }
  renderShelterMgt();saveData();
}
