document.addEventListener('focusin',function(e){
  var t=e.target;
  if(!t||(t.tagName!=='INPUT'&&t.tagName!=='TEXTAREA')) return;
  if(t.type==='checkbox'||t.type==='radio'||t.type==='number') return;
  var inEdit=t.closest&&(t.closest('.inline-edit-panel')||t.closest('.edit-toolbar')||(t.id&&t.id.indexOf('cfg-')===0));
  if(inEdit&&t.value){ setTimeout(function(){try{t.select();}catch(err){}},0); }
});
